const config = {
  "previewFeatures": [],
  "clientVersion": "7.7.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider   = \"prisma-client-js\"\n  output     = \"../src/generated/prisma\"\n  engineType = \"library\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// ─────────────────────────────────────────\n// TENANCY & AUTH\n// ─────────────────────────────────────────\n\nmodel Tenant {\n  id               String       @id @default(cuid())\n  name             String\n  slug             String       @unique\n  plan             Plan         @default(STARTER)\n  isPilot          Boolean      @default(false)\n  locale           String       @default(\"ro\")\n  status           TenantStatus @default(ACTIVE)\n  stripeCustomerId String?\n  createdAt        DateTime     @default(now())\n  updatedAt        DateTime     @updatedAt\n\n  users                 User[]\n  company               CompanyProfile?\n  departments           Department[]\n  jobs                  Job[]\n  sessions              EvaluationSession[]\n  compensationPkgs      CompensationPackage[]\n  kpiDefinitions        KpiDefinition[]\n  simulations           SimulationScenario[]\n  aiGenerations         AiGeneration[]\n  reports               Report[]\n  credits               CreditBalance?\n  creditTxns            CreditTransaction[]\n  salaryGrades          SalaryGrade[]\n  employeeSalaryRecords EmployeeSalaryRecord[]\n  payGapReports         PayGapReport[]\n  jointAssessments      JointPayAssessment[]\n  employeeRequests      EmployeeRequest[]\n  clientMemories        ClientMemory[]\n  payrollEntries        PayrollEntry[]\n  payrollImportBatches  PayrollImportBatch[]\n  revenueEntries        RevenueEntry[]\n  servicePurchase       ServicePurchase?\n  userOrgRoles          UserOrgRole[]\n  continuousReports     EmployeeContinuousReport[]\n  guideJournalEntries   GuideJournalEntry[]\n\n  @@map(\"tenants\")\n}\n\nmodel User {\n  id           String     @id @default(cuid())\n  tenantId     String\n  email        String\n  passwordHash String?\n  firstName    String\n  lastName     String\n  jobTitle     String?\n  role         UserRole   @default(REPRESENTATIVE)\n  locale       String     @default(\"ro\")\n  lastLogin    DateTime?\n  status       UserStatus @default(ACTIVE)\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n\n  tenant       Tenant      @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  department   Department? @relation(fields: [departmentId], references: [id])\n  departmentId String?\n\n  accounts               Account[]\n  authSessions           AuthSession[]\n  sessionParticipants    SessionParticipant[]\n  jobAssignments         JobAssignment[]\n  votes                  Vote[]\n  facilitatorDecisions   FacilitatorDecision[]\n  clarificationQuestions ClarificationQuestion[]\n  clarificationAnswers   ClarificationAnswer[]\n  overrides              ScoreOverride[]\n  notifications          Notification[]\n  representedJobs        Job[]                   @relation(\"JobRepresentative\")\n  validatedSessions      EvaluationSession[]     @relation(\"sessionValidator\")\n  discussionComments     DiscussionComment[]\n  memberValidations      MemberValidation[]\n\n  orgRoles UserOrgRole[]\n\n  @@unique([tenantId, email])\n  @@map(\"users\")\n}\n\n// ── Roluri organizaționale per user (many-to-many) ──────────────────────────\n\nmodel UserOrgRole {\n  id         String   @id @default(cuid())\n  userId     String\n  tenantId   String\n  orgRole    OrgRole\n  assignedBy String? // userId care a alocat rolul\n  assignedAt DateTime @default(now())\n\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, orgRole])\n  @@index([tenantId, orgRole])\n  @@map(\"user_org_roles\")\n}\n\n// ── Matrice permisiuni (seed-uită, nu editabilă de client) ──────────────────\n\nmodel PermissionRule {\n  id        String       @id @default(cuid())\n  orgRole   OrgRole\n  resource  PermResource\n  action    PermAction\n  minLayer  Int          @default(0) // 0 = fără layer, 1-4 = layer minim necesar\n  condition String? // condiție suplimentară (ex: \"own\" = doar propriile resurse)\n\n  @@unique([orgRole, resource, action])\n  @@index([orgRole])\n  @@map(\"permission_rules\")\n}\n\nmodel Account {\n  id                String  @id @default(cuid())\n  userId            String\n  type              String\n  provider          String\n  providerAccountId String\n  refresh_token     String?\n  access_token      String?\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String?\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n  @@map(\"accounts\")\n}\n\nmodel AuthSession {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"auth_sessions\")\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n  @@map(\"verification_tokens\")\n}\n\n// ─────────────────────────────────────────\n// COMPANY PROFILE\n// ─────────────────────────────────────────\n\nmodel CompanyProfile {\n  id                String    @id @default(cuid())\n  tenantId          String    @unique\n  mission           String?   @db.Text\n  vision            String?   @db.Text\n  values            String[]\n  description       String?   @db.Text\n  industry          String?\n  size              String?\n  website           String?\n  cui               String?\n  regCom            String?\n  address           String?\n  county            String?\n  caenCode          String?\n  caenName          String?\n  isVATPayer        Boolean?\n  logoUrl           String?\n  extractedAt       DateTime?\n  anafSyncedAt      DateTime?\n  // MVV Progressive Builder\n  mvvMaturity       String    @default(\"IMPLICIT\") // IMPLICIT | EMERGENT | PARTIAL | SUBSTANTIAL | COMPLETE\n  missionDraft      String?   @db.Text // generat AI\n  visionDraft       String?   @db.Text\n  valuesDraft       String[]\n  mvvLastBuiltAt    DateTime?\n  mvvLastBuiltFrom  String? // ce date au contribuit la ultimul rebuild\n  mvvCoherenceScore Float? // 0-100\n  mvvCoherenceGaps  Json? // [{level, gap, suggestion}]\n  mvvValidatedAt    DateTime? // când a confirmat clientul MVV-ul\n  createdAt         DateTime  @default(now())\n  updatedAt         DateTime  @updatedAt\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@map(\"company_profiles\")\n}\n\n// Company Profiler Engine — Punct 7: Memorie de evoluție\nmodel CompanyProfileSnapshot {\n  id             String   @id @default(cuid())\n  tenantId       String\n  maturityLevel  String // IMPLICIT | EMERGENT | PARTIAL | SUBSTANTIAL | COMPLETE\n  maturityScore  Float // 0-100\n  coherenceScore Float // 0-100\n  dataPoints     Json // DataPointPresence snapshot\n  readyServices  String[] // ServiceType[] active la momentul snapshot-ului\n  takenAt        DateTime @default(now())\n\n  @@index([tenantId, takenAt])\n  @@map(\"company_profile_snapshots\")\n}\n\nmodel Department {\n  id        String   @id @default(cuid())\n  tenantId  String\n  name      String\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  users  User[]\n  jobs   Job[]\n\n  @@unique([tenantId, name])\n  @@map(\"departments\")\n}\n\n// ─────────────────────────────────────────\n// FIȘE DE POST\n// ─────────────────────────────────────────\n\nmodel Job {\n  id               String           @id @default(cuid())\n  tenantId         String\n  departmentId     String?\n  representativeId String?\n  title            String\n  code             String?\n  purpose          String?          @db.Text\n  description      String?          @db.Text\n  responsibilities String?          @db.Text\n  requirements     String?          @db.Text\n  status           JobStatus        @default(DRAFT)\n  structureType    JobStructureType @default(HUMAN)\n  isActive         Boolean          @default(true)\n  aiAnalyzed       Boolean          @default(false)\n  aiAnalysis       Json?\n  createdBy        String           @default(\"\")\n  createdAt        DateTime         @default(now())\n  updatedAt        DateTime         @updatedAt\n\n  tenant         Tenant      @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  department     Department? @relation(fields: [departmentId], references: [id])\n  representative User?       @relation(\"JobRepresentative\", fields: [representativeId], references: [id])\n\n  sessionJobs          SessionJob[]\n  compensationPackages CompensationPackage[]\n  kpiDefinitions       KpiDefinition[]\n  simulations          SimulationScenario[]\n  jobResults           JobResult[]\n\n  @@map(\"jobs\")\n}\n\n// ─────────────────────────────────────────\n// CRITERII (GLOBALE — definite de platformă)\n// ─────────────────────────────────────────\n\nmodel Criterion {\n  id          String  @id @default(cuid())\n  name        String  @unique\n  description String? @db.Text\n  category    String?\n  order       Int\n  isActive    Boolean @default(true)\n\n  subfactors           Subfactor[]\n  evaluations          Evaluation[]\n  consensusStatuses    ConsensusStatus[]\n  votes                Vote[]\n  facilitatorDecisions FacilitatorDecision[]\n  overrides            ScoreOverride[]\n  discussionComments   DiscussionComment[]\n  memberValidations    MemberValidation[]\n\n  @@map(\"criteria\")\n}\n\nmodel Subfactor {\n  id          String @id @default(cuid())\n  criterionId String\n  code        String\n  description String @db.Text\n  points      Int\n  order       Int\n\n  criterion            Criterion             @relation(fields: [criterionId], references: [id])\n  evaluations          Evaluation[]\n  votes                Vote[]\n  facilitatorDecisions FacilitatorDecision[]\n  overrides            ScoreOverride[]\n  consensuses          ConsensusStatus[]\n\n  @@unique([criterionId, code])\n  @@map(\"subfactors\")\n}\n\n// ─────────────────────────────────────────\n// SESIUNI DE EVALUARE\n// ─────────────────────────────────────────\n\nmodel EvaluationSession {\n  id                 String         @id @default(cuid())\n  tenantId           String\n  name               String\n  status             SessionStatus  @default(DRAFT)\n  evaluationType     EvaluationType @default(AI_GENERATED)\n  currentRound       Int            @default(1)\n  consensusThreshold Float          @default(0.75)\n  deadline           DateTime?\n  startedAt          DateTime?\n  completedAt        DateTime?\n  validatedAt        DateTime?\n  validatedBy        String?\n  signatureData      String?        @db.Text // base64 PNG semnătură olografă\n  signedAt           DateTime?\n  createdById        String         @default(\"\")\n  createdAt          DateTime       @default(now())\n  updatedAt          DateTime       @updatedAt\n\n  tenant    Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  validator User?  @relation(\"sessionValidator\", fields: [validatedBy], references: [id])\n\n  sessionJobs          SessionJob[]\n  participants         SessionParticipant[]\n  evaluations          Evaluation[]\n  consensusStatuses    ConsensusStatus[]\n  votes                Vote[]\n  facilitatorDecisions FacilitatorDecision[]\n  clarifications       ClarificationQuestion[]\n  jobResults           JobResult[]\n  salaryGrades         SalaryGrade[]\n  overrides            ScoreOverride[]\n  discussionComments   DiscussionComment[]\n  memberValidations    MemberValidation[]\n\n  @@map(\"evaluation_sessions\")\n}\n\nmodel SessionJob {\n  id        String   @id @default(cuid())\n  sessionId String\n  jobId     String\n  createdAt DateTime @default(now())\n\n  session     EvaluationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  job         Job               @relation(fields: [jobId], references: [id])\n  assignments JobAssignment[]\n\n  @@unique([sessionId, jobId])\n  @@map(\"session_jobs\")\n}\n\nmodel SessionParticipant {\n  id          String    @id @default(cuid())\n  sessionId   String\n  userId      String\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n\n  session EvaluationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  user    User              @relation(fields: [userId], references: [id])\n\n  @@unique([sessionId, userId])\n  @@map(\"session_participants\")\n}\n\nmodel JobAssignment {\n  id           String    @id @default(cuid())\n  sessionJobId String\n  userId       String\n  submittedAt  DateTime?\n  createdAt    DateTime  @default(now())\n\n  sessionJob  SessionJob   @relation(fields: [sessionJobId], references: [id], onDelete: Cascade)\n  user        User         @relation(fields: [userId], references: [id])\n  evaluations Evaluation[]\n\n  @@unique([sessionJobId, userId])\n  @@map(\"job_assignments\")\n}\n\n// ─────────────────────────────────────────\n// EVALUARE / SCORARE\n// ─────────────────────────────────────────\n\nmodel Evaluation {\n  id            String   @id @default(cuid())\n  sessionId     String\n  assignmentId  String\n  criterionId   String\n  subfactorId   String\n  justification String?  @db.Text\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  session    EvaluationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  assignment JobAssignment     @relation(fields: [assignmentId], references: [id], onDelete: Cascade)\n  criterion  Criterion         @relation(fields: [criterionId], references: [id])\n  subfactor  Subfactor         @relation(fields: [subfactorId], references: [id])\n\n  @@unique([assignmentId, criterionId])\n  @@map(\"evaluations\")\n}\n\n// ─────────────────────────────────────────\n// CLARIFICĂRI\n// ─────────────────────────────────────────\n\nmodel ClarificationQuestion {\n  id          String   @id @default(cuid())\n  sessionId   String\n  jobId       String\n  criterionId String\n  question    String   @db.Text\n  askedBy     String\n  createdAt   DateTime @default(now())\n\n  session EvaluationSession    @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  asker   User                 @relation(fields: [askedBy], references: [id])\n  answer  ClarificationAnswer?\n\n  @@map(\"clarification_questions\")\n}\n\nmodel ClarificationAnswer {\n  id         String   @id @default(cuid())\n  questionId String   @unique\n  answer     String   @db.Text\n  answeredBy String\n  createdAt  DateTime @default(now())\n\n  question ClarificationQuestion @relation(fields: [questionId], references: [id])\n  answerer User                  @relation(fields: [answeredBy], references: [id])\n\n  @@map(\"clarification_answers\")\n}\n\n// ─────────────────────────────────────────\n// CONSENS\n// ─────────────────────────────────────────\n\nmodel ConsensusStatus {\n  id               String         @id @default(cuid())\n  sessionId        String\n  jobId            String\n  criterionId      String\n  status           ConsensusState @default(PENDING)\n  round1Cv         Float?\n  round2Cv         Float?\n  finalSubfactorId String?\n  updatedAt        DateTime       @updatedAt\n\n  session        EvaluationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  criterion      Criterion         @relation(fields: [criterionId], references: [id])\n  finalSubfactor Subfactor?        @relation(fields: [finalSubfactorId], references: [id])\n\n  @@unique([sessionId, jobId, criterionId])\n  @@map(\"consensus_statuses\")\n}\n\nmodel Vote {\n  id          String   @id @default(cuid())\n  sessionId   String\n  jobId       String\n  criterionId String\n  userId      String\n  subfactorId String\n  round       Int      @default(1)\n  createdAt   DateTime @default(now())\n\n  session   EvaluationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  user      User              @relation(fields: [userId], references: [id])\n  criterion Criterion         @relation(fields: [criterionId], references: [id])\n  subfactor Subfactor         @relation(fields: [subfactorId], references: [id])\n\n  @@unique([sessionId, jobId, criterionId, userId])\n  @@map(\"votes\")\n}\n\nmodel FacilitatorDecision {\n  id            String   @id @default(cuid())\n  sessionId     String\n  jobId         String\n  criterionId   String\n  facilitatorId String\n  subfactorId   String\n  rationale     String   @db.Text\n  createdAt     DateTime @default(now())\n\n  session     EvaluationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  facilitator User              @relation(fields: [facilitatorId], references: [id])\n  criterion   Criterion         @relation(fields: [criterionId], references: [id])\n  subfactor   Subfactor         @relation(fields: [subfactorId], references: [id])\n\n  @@unique([sessionId, jobId, criterionId])\n  @@map(\"facilitator_decisions\")\n}\n\n// ─────────────────────────────────────────\n// DISCUȚIE GRUP (Bloc 3)\n// ─────────────────────────────────────────\n\nmodel DiscussionComment {\n  id          String   @id @default(cuid())\n  sessionId   String\n  jobId       String\n  criterionId String\n  userId      String? // null = AI mediator\n  round       Int      @default(1)\n  content     String   @db.Text\n  isAi        Boolean  @default(false)\n  parentId    String? // reply threading\n  createdAt   DateTime @default(now())\n\n  session   EvaluationSession   @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  user      User?               @relation(fields: [userId], references: [id])\n  criterion Criterion           @relation(fields: [criterionId], references: [id])\n  parent    DiscussionComment?  @relation(\"CommentReplies\", fields: [parentId], references: [id])\n  replies   DiscussionComment[] @relation(\"CommentReplies\")\n\n  @@index([sessionId, jobId, criterionId])\n  @@map(\"discussion_comments\")\n}\n\n// ─────────────────────────────────────────\n// VALIDARE POST-CONSENS (Bloc 4)\n// ─────────────────────────────────────────\n\nmodel MemberValidation {\n  id          String    @id @default(cuid())\n  sessionId   String\n  jobId       String\n  userId      String\n  criterionId String\n  preScore    String // litera pre-scorare originală (ex: \"D\")\n  consensus   String // litera consens final (ex: \"E\")\n  accepted    Boolean   @default(false)\n  acceptedAt  DateTime?\n  createdAt   DateTime  @default(now())\n\n  session   EvaluationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  user      User              @relation(fields: [userId], references: [id])\n  criterion Criterion         @relation(fields: [criterionId], references: [id])\n\n  @@unique([sessionId, jobId, userId, criterionId])\n  @@map(\"member_validations\")\n}\n\n// ─────────────────────────────────────────\n// REZULTATE & CLASIFICARE\n// ─────────────────────────────────────────\n\nmodel JobResult {\n  id              String   @id @default(cuid())\n  sessionId       String\n  jobId           String\n  totalScore      Int\n  normalizedScore Float\n  rank            Int\n  salaryGradeId   String?\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n\n  session     EvaluationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  job         Job               @relation(fields: [jobId], references: [id])\n  salaryGrade SalaryGrade?      @relation(fields: [salaryGradeId], references: [id])\n\n  @@unique([sessionId, jobId])\n  @@map(\"job_results\")\n}\n\nmodel SalaryGrade {\n  id        String   @id @default(cuid())\n  tenantId  String\n  sessionId String\n  name      String\n  scoreMin  Int\n  scoreMax  Int\n  salaryMin Float?\n  salaryMax Float?\n  currency  String   @default(\"RON\")\n  order     Int\n  createdAt DateTime @default(now())\n\n  tenant                Tenant                 @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  session               EvaluationSession      @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  jobResults            JobResult[]\n  employeeSalaryRecords EmployeeSalaryRecord[]\n  employeeRequests      EmployeeRequest[]\n  steps                 SalaryStep[]\n\n  @@map(\"salary_grades\")\n}\n\nmodel SalaryStep {\n  id            String   @id @default(cuid())\n  salaryGradeId String\n  step          Int\n  name          String\n  salary        Decimal\n  criteria      String?\n  createdAt     DateTime @default(now())\n\n  grade SalaryGrade @relation(fields: [salaryGradeId], references: [id], onDelete: Cascade)\n\n  @@unique([salaryGradeId, step])\n  @@index([salaryGradeId, step])\n  @@map(\"salary_steps\")\n}\n\n// ─────────────────────────────────────────\n// PAY GAP ANALYTICS (EU 2023/970 Art. 9)\n// ─────────────────────────────────────────\n\nmodel EmployeeSalaryRecord {\n  id                  String   @id @default(cuid())\n  tenantId            String\n  salaryGradeId       String?\n  employeeCode        String // cod intern platforma (generat sau din client)\n  companyEmployeeId   String? // ID alocat de client (poate fi null inițial)\n  internalFingerprint String? // hash din (jobTitle+dept+gender+salary) pt matching fără ID\n  gender              Gender\n  baseSalary          Float\n  variableComp        Float    @default(0)\n  department          String?\n  jobCategory         String?\n  workSchedule        String?  @default(\"8h\") // normă lucru: 2h, 4h, 6h, 8h\n  evaluationScore     Int? // scor total din Modul 1 (muncă egală = scor egal)\n  periodYear          Int\n  periodMonth         Int?\n  createdAt           DateTime @default(now())\n  updatedAt           DateTime @updatedAt\n\n  tenant      Tenant       @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  salaryGrade SalaryGrade? @relation(fields: [salaryGradeId], references: [id])\n\n  @@unique([tenantId, employeeCode, periodYear])\n  @@index([tenantId, companyEmployeeId])\n  @@index([tenantId, internalFingerprint])\n  @@map(\"employee_salary_records\")\n}\n\nmodel PayGapReport {\n  id            String       @id @default(cuid())\n  tenantId      String\n  reportYear    Int\n  indicators    Json\n  employeeCount Int\n  status        ReportStatus @default(DRAFT)\n  publishedAt   DateTime?\n  generatedAt   DateTime     @default(now())\n  generatedBy   String\n\n  tenant           Tenant               @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  jointAssessments JointPayAssessment[]\n\n  @@unique([tenantId, reportYear])\n  @@map(\"pay_gap_reports\")\n}\n\nmodel JointPayAssessment {\n  id            String           @id @default(cuid())\n  tenantId      String\n  reportId      String?\n  triggeredAt   DateTime         @default(now())\n  triggerReason String           @db.Text\n  status        AssessmentStatus @default(OPEN)\n  rootCause     String?          @db.Text\n  actionPlan    Json?\n  dueDate       DateTime?\n  resolvedAt    DateTime?\n  createdBy     String\n\n  tenant Tenant        @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  report PayGapReport? @relation(fields: [reportId], references: [id])\n\n  @@map(\"joint_pay_assessments\")\n}\n\n// ─────────────────────────────────────────\n// EMPLOYEE PORTAL (EU 2023/970 Art. 7)\n// ─────────────────────────────────────────\n\nmodel EmployeeRequest {\n  id             String        @id @default(cuid())\n  tenantId       String\n  requestedBy    String\n  requestEmail   String\n  salaryGradeId  String?\n  requestType    String        @default(\"ART7\")\n  status         RequestStatus @default(PENDING)\n  requestDetails String?       @db.Text\n  response       String?       @db.Text\n  respondedAt    DateTime?\n  respondedBy    String?\n  dueDate        DateTime\n  createdAt      DateTime      @default(now())\n  updatedAt      DateTime      @updatedAt\n\n  tenant      Tenant       @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  salaryGrade SalaryGrade? @relation(fields: [salaryGradeId], references: [id])\n\n  @@map(\"employee_requests\")\n}\n\n// ─────────────────────────────────────────\n// RAPORT ANGAJAT CONTINUU (document viu transversal)\n// ─────────────────────────────────────────\n\nmodel EmployeeContinuousReport {\n  id                String                 @id @default(cuid())\n  tenantId          String\n  employeeName      String // Nume angajat (nu neapărat user)\n  employeeEmail     String?\n  jobTitle          String? // Postul curent\n  department        String?\n  visibleToEmployee Boolean                @default(false) // bifă angajator → GDPR Art. 15\n  status            ContinuousReportStatus @default(ACTIVE)\n  createdAt         DateTime               @default(now())\n  updatedAt         DateTime               @updatedAt\n\n  tenant   Tenant                  @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  sections EmployeeReportSection[]\n\n  @@unique([tenantId, employeeEmail])\n  @@index([tenantId])\n  @@map(\"employee_continuous_reports\")\n}\n\nmodel EmployeeReportSection {\n  id        String       @id @default(cuid())\n  reportId  String\n  module    ReportModule // care modul a generat secțiunea\n  title     String\n  content   Json // conținut structurat (diferă per modul)\n  order     Int          @default(0)\n  version   Int          @default(1) // document viu — versiuni\n  createdAt DateTime     @default(now())\n  updatedAt DateTime     @updatedAt\n\n  report EmployeeContinuousReport @relation(fields: [reportId], references: [id], onDelete: Cascade)\n\n  @@index([reportId, module])\n  @@map(\"employee_report_sections\")\n}\n\n// ─────────────────────────────────────────\n// JURNAL GHID JOBGRADE (feedback loop antrenare)\n// ─────────────────────────────────────────\n\nmodel GuideJournalEntry {\n  id          String   @id @default(cuid())\n  tenantId    String\n  userId      String?\n  page        String // pagina/context\n  question    String   @db.Text\n  answer      String   @db.Text\n  helpful     Boolean? // feedback: a fost util?\n  category    String? // clasificare automată\n  delegatedTo String? // agentul delegat (SOA, CSSA, etc.)\n  createdAt   DateTime @default(now())\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId, page])\n  @@index([tenantId, category])\n  @@map(\"guide_journal_entries\")\n}\n\nmodel ScoreOverride {\n  id          String   @id @default(cuid())\n  sessionId   String\n  jobId       String\n  criterionId String\n  ownerId     String\n  subfactorId String\n  rationale   String   @db.Text\n  createdAt   DateTime @default(now())\n\n  session   EvaluationSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n  owner     User              @relation(fields: [ownerId], references: [id])\n  criterion Criterion         @relation(fields: [criterionId], references: [id])\n  subfactor Subfactor         @relation(fields: [subfactorId], references: [id])\n\n  @@map(\"score_overrides\")\n}\n\n// ─────────────────────────────────────────\n// COMPENSAȚII & SIMULĂRI\n// ─────────────────────────────────────────\n\nmodel CompensationPackage {\n  id         String   @id @default(cuid())\n  tenantId   String\n  jobId      String\n  baseSalary Float\n  currency   String   @default(\"RON\")\n  components Json\n  benefits   Json?\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  tenant      Tenant               @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  job         Job                  @relation(fields: [jobId], references: [id])\n  simulations SimulationScenario[]\n\n  @@map(\"compensation_packages\")\n}\n\nmodel KpiDefinition {\n  id              String       @id @default(cuid())\n  tenantId        String\n  jobId           String\n  name            String\n  weight          Float\n  targetValue     Float\n  measurementUnit String\n  frequency       KpiFrequency @default(MONTHLY)\n  createdAt       DateTime     @default(now())\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  job    Job    @relation(fields: [jobId], references: [id])\n\n  @@map(\"kpi_definitions\")\n}\n\nmodel SimulationScenario {\n  id               String   @id @default(cuid())\n  tenantId         String\n  jobId            String\n  packageId        String\n  name             String\n  kpiAchievements  Json\n  calculatedResult Json\n  createdBy        String\n  createdAt        DateTime @default(now())\n\n  tenant  Tenant              @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n  job     Job                 @relation(fields: [jobId], references: [id])\n  package CompensationPackage @relation(fields: [packageId], references: [id])\n\n  @@map(\"simulation_scenarios\")\n}\n\n// ─────────────────────────────────────────\n// AI GENERĂRI\n// ─────────────────────────────────────────\n\nmodel AiGeneration {\n  id         String           @id @default(cuid())\n  tenantId   String\n  type       AiGenerationType\n  sourceId   String?\n  sourceType String?\n  prompt     String           @db.Text\n  output     String           @db.Text\n  model      String\n  tokensUsed Int\n  credits    Int\n  createdAt  DateTime         @default(now())\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId, createdAt])\n  @@map(\"ai_generations\")\n}\n\n// ─────────────────────────────────────────\n// RAPOARTE\n// ─────────────────────────────────────────\n\nmodel Report {\n  id          String       @id @default(cuid())\n  tenantId    String\n  sessionId   String?\n  type        ReportType\n  format      ReportFormat\n  sections    String[]\n  locale      String       @default(\"ro\")\n  filePath    String?\n  generatedBy String\n  createdAt   DateTime     @default(now())\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId, type])\n  @@map(\"reports\")\n}\n\n// ─────────────────────────────────────────\n// CREDITE & BILLING\n// ─────────────────────────────────────────\n\nmodel CreditBalance {\n  id        String   @id @default(cuid())\n  tenantId  String   @unique\n  balance   Int      @default(0)\n  updatedAt DateTime @updatedAt\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@map(\"credit_balances\")\n}\n\nmodel CreditTransaction {\n  id          String        @id @default(cuid())\n  tenantId    String\n  type        CreditTxnType\n  amount      Int\n  description String\n  sourceId    String?\n  createdAt   DateTime      @default(now())\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId, createdAt])\n  @@map(\"credit_transactions\")\n}\n\n// ─────────────────────────────────────────\n// BUGET OPERAȚIONAL\n// ─────────────────────────────────────────\n\nmodel BudgetLine {\n  id         String         @id @default(cuid())\n  businessId String\n  category   BudgetCategory\n  month      DateTime // primul zi a lunii (ex: 2026-07-01)\n  planned    Decimal        @default(0)\n  actual     Decimal        @default(0)\n  notes      String?\n  approvedBy String? // userId care a aprobat\n  createdAt  DateTime       @default(now())\n  updatedAt  DateTime       @updatedAt\n\n  @@unique([businessId, category, month])\n  @@index([businessId, month])\n  @@map(\"budget_lines\")\n}\n\nmodel RevenueEntry {\n  id              String      @id @default(cuid())\n  tenantId        String\n  type            RevenueType\n  amount          Decimal\n  currency        String      @default(\"RON\")\n  description     String?\n  stripePaymentId String? // legătură cu Stripe\n  periodMonth     DateTime // luna la care se referă\n  createdAt       DateTime    @default(now())\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId, periodMonth])\n  @@map(\"revenue_entries\")\n}\n\n// ─────────────────────────────────────────\n// SERVICE PURCHASE (pachet servicii B2B)\n// ─────────────────────────────────────────\n\nmodel ServicePurchase {\n  id              String   @id @default(cuid())\n  tenantId        String   @unique\n  layer           Int // 1=Baza, 2=Conformitate, 3=Competitivitate, 4=Dezvoltare (max cumparat)\n  positions       Int // nr pozitii la momentul achizitiei\n  employees       Int // nr salariati la momentul achizitiei\n  priceRON        Int // pretul platit in RON\n  stripeSessionId String?\n  status          String   @default(\"ACTIVE\") // ACTIVE, EXPIRED\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@map(\"service_purchases\")\n}\n\nenum BudgetCategory {\n  INFRA // Vercel, Neon, domenii\n  API_AI // Claude API (Haiku/Sonnet)\n  MARKETING // Campanii, materiale\n  PERSONAL // Psihologi, DPO, colaboratori\n  REVENUE // Venituri (planned vs actual)\n  DIVERSE // Contingency, neprevăzut\n}\n\nenum RevenueType {\n  SUBSCRIPTION // Abonament lunar/anual\n  CREDITS // Achiziție pachete credite\n  SERVICE // Plată per serviciu/proiect\n  REFUND // Rambursare\n}\n\n// ─────────────────────────────────────────\n// NOTIFICĂRI\n// ─────────────────────────────────────────\n\nmodel Notification {\n  id        String           @id @default(cuid())\n  userId    String\n  type      NotificationType\n  title     String\n  body      String\n  link      String?\n  read      Boolean          @default(false)\n  createdAt DateTime         @default(now())\n\n  // ── Cerere structurată de la agent ──\n  sourceRole   String? // Agentul care solicită (COG, DOA, etc.)\n  requestKind  OwnerRequestKind? // Ce tip de răspuns așteaptă\n  requestData  String?            @db.Text // JSON: detalii specifice cererii\n  responseKind OwnerResponseKind? // Ce a răspuns Owner-ul\n  responseData String?            @db.Text // JSON: datele/acțiunea furnizată\n  respondedAt  DateTime? // Când a răspuns\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId, read, createdAt])\n  @@map(\"notifications\")\n}\n\n// ─────────────────────────────────────────\n// KNOWLEDGE BASE (KB)\n// ─────────────────────────────────────────\n\nmodel KBEntry {\n  id             String                       @id @default(cuid())\n  agentRole      String // ex: \"HR_COUNSELOR\", \"PSYCHOLINGUIST\"\n  kbType         KBType\n  content        String                       @db.Text\n  embedding      Unsupported(\"vector(1024)\")?\n  source         KBSource\n  confidence     Float                        @default(0)\n  usageCount     Int                          @default(0)\n  successRate    Float?\n  status         KBStatus                     @default(BUFFER)\n  tags           String[]\n  createdAt      DateTime                     @default(now())\n  validatedAt    DateTime?\n  propagatedFrom String? // agentRole sursă dacă e propagat\n\n  @@index([agentRole, status])\n  @@index([agentRole, kbType])\n  @@map(\"kb_entries\")\n}\n\nmodel KBBuffer {\n  id               String    @id @default(cuid())\n  agentRole        String\n  rawContent       String    @db.Text\n  sessionRef       String?\n  occurrences      Int       @default(1)\n  positiveOutcomes Int       @default(0)\n  totalOutcomes    Int       @default(0)\n  status           String    @default(\"PENDING\") // PENDING|APPROVED|REJECTED\n  createdAt        DateTime  @default(now())\n  reviewedAt       DateTime?\n\n  @@index([agentRole, status])\n  @@map(\"kb_buffers\")\n}\n\n// ─────────────────────────────────────────\n// ENUMS\n// ─────────────────────────────────────────\n\nenum Plan {\n  STARTER\n  PROFESSIONAL\n  ENTERPRISE\n}\n\nenum TenantStatus {\n  ACTIVE\n  SUSPENDED\n  CANCELLED\n}\n\nenum UserRole {\n  SUPER_ADMIN\n  COMPANY_ADMIN\n  OWNER\n  FACILITATOR\n  REPRESENTATIVE\n}\n\nenum UserStatus {\n  ACTIVE\n  INACTIVE\n  INVITED\n}\n\n// ── Roluri organizaționale (mapate la drepturi platformă) ────────────────────\n\nenum OrgRole {\n  DG // Director General / Owner\n  IDG // Împuternicit DG (pe probleme HR)\n  DHR // Director HR\n  RSAL // Responsabil Salarizare (Comp & Ben)\n  RREC // Responsabil Recrutare\n  RAP // Responsabil Administrare Personal (include relații de muncă)\n  RLD // Responsabil Learning & Development\n  FJE // Facilitator Evaluare Posturi\n  FA10 // Facilitator Evaluare Comună Art. 10\n  REPS // Reprezentant Salariați\n  REPM // Reprezentant Management\n  CEXT // Consultant Extern\n  SAL // Salariat (angajat fără funcție HR)\n}\n\nenum PermAction {\n  READ\n  WRITE\n  MODIFY // delete, archive, approve\n}\n\nenum PermResource {\n  JOBS // Posturi\n  JOB_POSTINGS // Anunțuri posturi publice (Art. 5)\n  SESSIONS // Sesiuni evaluare posturi\n  SALARY_GRADES // Clase salariale + trepte\n  SALARY_DATA // Date salariale angajați (import/gestionare)\n  PAY_GAP_REPORT // Raport pay gap (Art. 9)\n  PAY_GAP_JUSTIFICATIONS // Justificări diferențe\n  JOINT_ASSESSMENT // Evaluare comună (Art. 10)\n  EMPLOYEE_REQUESTS // Cereri angajați (Art. 7)\n  COMPLIANCE_REPORT // Raport conformitate PDF\n  BENCHMARK // Benchmark piață\n  PERSONNEL_EVAL // Evaluare personal\n  ORG_DEVELOPMENT // Dezvoltare organizațională\n  SETTINGS // Setări cont\n  BILLING // Facturare, abonament\n  USERS // Gestiune utilizatori\n  AUDIT_TRAIL // Jurnal audit\n}\n\nenum JobStatus {\n  DRAFT\n  ACTIVE\n  ARCHIVED\n}\n\nenum JobStructureType {\n  HUMAN // Post uman clasic\n  AI // Post AI (agent)\n  MIXED // Post mixt (om + AI)\n}\n\nenum SessionStatus {\n  DRAFT\n  BENCHMARK_SELECTION // AI sugerează, admin ajustează (Sprint 6)\n  PRE_SCORING // Evaluatori scorează individual, asincron (Sprint 5)\n  IN_PROGRESS // Sesiune grup: comparare, consens, mediere\n  RECALIBRATION\n  VOTING\n  FACILITATION\n  SLOTTING // Non-benchmarks se clasifică rapid (Sprint 6)\n  OWNER_VALIDATION // Owner revizuiește, ajustează din MVV (Sprint 7)\n  COMPLETED\n  VALIDATED // Validare finală de Director General / reprezentant legal\n}\n\nenum EvaluationType {\n  AI_GENERATED // Parcurs A: evaluare generată integral de AI\n  AI_COMMITTEE // Parcurs B: AI generează T0, comisia dezbate și ajustează\n  COMMITTEE_ONLY // Parcurs C: comisie pură, fără AI\n}\n\nenum ConsensusState {\n  PENDING\n  CONSENSUS\n  RECALIBRATING\n  VOTING\n  FACILITATED\n  RESOLVED\n}\n\nenum KpiFrequency {\n  MONTHLY\n  QUARTERLY\n  ANNUALLY\n}\n\nenum AiGenerationType {\n  JOB_AD\n  SOCIAL_MEDIA\n  KPI_SHEET\n  SESSION_ANALYSIS\n  JOB_ANALYSIS\n  COMPANY_EXTRACT\n}\n\nenum ReportType {\n  HIERARCHY\n  SALARY_GRADES\n  KPI\n  BUDGET\n  FULL\n}\n\nenum ReportFormat {\n  PDF\n  EXCEL\n}\n\nenum CreditTxnType {\n  PURCHASE\n  SUBSCRIPTION_MONTHLY\n  USAGE\n  REFUND\n}\n\nenum NotificationType {\n  SESSION_LAUNCHED\n  EVALUATOR_COMPLETED\n  ALL_COMPLETED\n  CONSENSUS_REACHED\n  RECALIBRATION_STARTED\n  VOTE_STARTED\n  FACILITATOR_NEEDED\n  CLARIFICATION_RECEIVED\n  CLARIFICATION_ANSWERED\n  REPORT_GENERATED\n  CREDITS_LOW\n  INVOICE_ISSUED\n  EMPLOYEE_REQUEST_RECEIVED\n  EMPLOYEE_REQUEST_OVERDUE\n  PAY_GAP_THRESHOLD_EXCEEDED\n  COG_MESSAGE\n  AGENT_MESSAGE\n  OWNER_REQUEST // Cerere structurată de la structură către Owner\n}\n\n// Ce tip de răspuns așteaptă agentul de la Owner\nenum OwnerRequestKind {\n  INFORMATION // Agentul are nevoie de date/informații specifice\n  ACCESS // Agentul cere acces la o resursă/funcționalitate\n  DECISION // Agentul cere o decizie strategică (aprob/resping/ajustez)\n  ACTION // Agentul cere Owner-ului să facă ceva concret\n  VALIDATION // Agentul cere validarea unui rezultat/raport\n}\n\n// Ce a furnizat Owner-ul ca răspuns\nenum OwnerResponseKind {\n  INFO_PROVIDED // A furnizat informația cerută\n  ACCESS_GRANTED // A acordat accesul\n  ACCESS_DENIED // A refuzat accesul\n  APPROVED // A aprobat\n  REJECTED // A respins\n  ADJUSTED // A aprobat cu modificări\n  ACTION_DONE // A executat acțiunea cerută\n  VALIDATED // A validat rezultatul\n  DELEGATED // A delegat altcuiva\n  CLARIFICATION // A cerut lămuriri suplimentare\n}\n\nenum Gender {\n  MALE\n  FEMALE\n  OTHER\n}\n\nenum ReportStatus {\n  DRAFT\n  PUBLISHED\n  ARCHIVED\n}\n\nenum ContinuousReportStatus {\n  ACTIVE\n  SUSPENDED // angajat plecat temporar\n  CLOSED // angajat plecat definitiv\n}\n\nenum ReportModule {\n  JOB_EVALUATION // Modul 1 — evaluare posturi\n  SALARY_TRANSPARENCY // Modul 2 — transparență salarială\n  PAY_GAP // Modul 2 — raport pay gap\n  JOINT_ASSESSMENT // Modul 2 — evaluare comună\n  BENCHMARK // Modul 3 — benchmark piață\n  PERSONNEL_EVAL // Modul 4 — evaluare personal\n  ORG_DEVELOPMENT // Modul 4 — dezvoltare organizațională\n  CUSTOM // Secțiune manuală\n}\n\nenum AssessmentStatus {\n  OPEN\n  IN_PROGRESS\n  RESOLVED\n  CLOSED\n}\n\nenum RequestStatus {\n  PENDING\n  IN_REVIEW\n  RESPONDED\n  OVERDUE\n}\n\nenum KBType {\n  PERMANENT // KB personal al agentului\n  SHARED_DOMAIN // KB domeniu partajat (ex: HR general)\n  CLIENT_LEXICON // lexicon extras din docs client\n  METHODOLOGY // metodologia JobGrade — read-only\n}\n\nenum KBSource {\n  SELF_INTERVIEW // pre-populare via Claude self-interview\n  EXPERT_HUMAN // input direct de la fondatori\n  DISTILLED_INTERACTION // distilat din sesiuni reale\n  PROPAGATED // primit de la alt agent\n}\n\nenum KBStatus {\n  BUFFER // nevalidat încă\n  PERMANENT // validat, activ\n  ARCHIVED // deprecat\n}\n\n// ── Proactive Management ──────────────────────────────────────────────────────\n\nmodel CycleLog {\n  id           String    @id @default(cuid())\n  managerRole  String\n  targetRole   String\n  actionType   String // TRACK, INTERVENE, ESCALATE\n  description  String    @db.Text\n  details      String?   @db.Text\n  escalationId String?\n  resolved     Boolean   @default(false)\n  createdAt    DateTime  @default(now())\n  resolvedAt   DateTime?\n\n  @@index([managerRole, resolved])\n  @@index([targetRole, actionType])\n  @@map(\"cycle_logs\")\n}\n\nmodel Escalation {\n  id              String    @id @default(cuid())\n  externalId      String    @unique // ESC-timestamp-random\n  sourceRole      String\n  targetRole      String\n  aboutRole       String\n  reason          String    @db.Text\n  details         String?   @db.Text\n  priority        String // CRITICAL, HIGH, MEDIUM, LOW\n  status          String    @default(\"OPEN\") // OPEN, IN_PROGRESS, RESOLVED, ESCALATED_UP, TIMEOUT\n  resolution      String?   @db.Text\n  timeoutHours    Int       @default(24)\n  escalatedFromId String? // ID escalare anterioară\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n  resolvedAt      DateTime?\n\n  @@index([targetRole, status])\n  @@index([sourceRole, status])\n  @@index([status])\n  @@map(\"escalations\")\n}\n\n// ── Agent Registry (dynamic org chart) ───────────────────────────────────────\n\nmodel AgentDefinition {\n  id          String     @id @default(cuid())\n  agentRole   String     @unique\n  displayName String\n  description String     @db.Text\n  level       AgentLevel\n  isManager   Boolean    @default(false)\n  isActive    Boolean    @default(true)\n\n  // Mod de activitate — folosit de detectorul de disfuncții pentru a calibra\n  // ce înseamnă \"lipsă de activitate\" pentru fiecare agent. Vezi\n  // project_disfunction_detection_principle.md (05.04.2026).\n  activityMode AgentActivityMode @default(PROACTIVE_CYCLIC)\n\n  // Manager-specific\n  cycleIntervalHours Int?\n  objectives         String[]\n  thresholds         Json?\n\n  // Cold start config\n  coldStartDescription String?  @db.Text\n  coldStartPrompts     String[]\n\n  // Propagation rules (outgoing edges)\n  propagationTargets Json?\n\n  // Metadata\n  createdBy String   @default(\"SYSTEM\")\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  parentRelations AgentRelationship[] @relation(\"ChildAgent\")\n  childRelations  AgentRelationship[] @relation(\"ParentAgent\")\n  proposals       OrgProposal[]       @relation(\"ProposalAgent\")\n  metrics         AgentMetric[]\n\n  @@index([level, isActive])\n  @@map(\"agent_definitions\")\n}\n\nmodel AgentRelationship {\n  id           String       @id @default(cuid())\n  parentRole   String\n  childRole    String\n  relationType RelationType @default(REPORTS_TO)\n  isActive     Boolean      @default(true)\n  createdAt    DateTime     @default(now())\n\n  parent AgentDefinition @relation(\"ParentAgent\", fields: [parentRole], references: [agentRole])\n  child  AgentDefinition @relation(\"ChildAgent\", fields: [childRole], references: [agentRole])\n\n  @@unique([parentRole, childRole])\n  @@index([parentRole, isActive])\n  @@map(\"agent_relationships\")\n}\n\nmodel OrgProposal {\n  id           String         @id @default(cuid())\n  proposalType ProposalType\n  status       ProposalStatus @default(DRAFT)\n  proposedBy   String\n  title        String\n  description  String         @db.Text\n  rationale    String         @db.Text\n  impact       Json?\n  changeSpec   Json\n\n  reviewedByCog Boolean        @default(false)\n  cogComment    String?        @db.Text\n  ownerDecision OwnerDecision?\n  ownerComment  String?        @db.Text\n\n  executedAt DateTime?\n  rollbackAt DateTime?\n\n  agentRole String?\n  agent     AgentDefinition? @relation(\"ProposalAgent\", fields: [agentRole], references: [agentRole])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([status])\n  @@index([proposedBy])\n  @@map(\"org_proposals\")\n}\n\nmodel AgentMetric {\n  id          String   @id @default(cuid())\n  agentRole   String\n  periodStart DateTime\n  periodEnd   DateTime\n\n  tasksCompleted    Int    @default(0)\n  tasksEscalated    Int    @default(0)\n  avgResponseTimeMs Int?\n  kbEntriesAdded    Int    @default(0)\n  kbEntriesUsed     Int    @default(0)\n  propagationsOut   Int    @default(0)\n  propagationsIn    Int    @default(0)\n  healthScoreAvg    Float?\n  cycleActions      Int    @default(0)\n  performanceScore  Float?\n\n  createdAt DateTime @default(now())\n\n  agent AgentDefinition @relation(fields: [agentRole], references: [agentRole])\n\n  @@unique([agentRole, periodStart, periodEnd])\n  @@index([agentRole, periodStart])\n  @@map(\"agent_metrics\")\n}\n\n// ── Agent Registry Enums ─────────────────────────────────────────────────────\n\nenum AgentLevel {\n  STRATEGIC\n  TACTICAL\n  OPERATIONAL\n}\n\n/// Mod de activitate așteptat al unui agent.\n///\n/// Folosit de FLUX-045 (role-activity monitor) pentru a calibra ce înseamnă\n/// \"lipsă de activitate\" pentru fiecare agent. Diferite moduri implică praguri\n/// și semnale diferite — un agent REACTIVE_TRIGGERED care stă 72h fără activitate\n/// e comportament normal, nu disfuncție.\nenum AgentActivityMode {\n  /// Agent cu ciclu propriu de activitate (cron la cycleIntervalHours).\n  /// Detectorul raportează `no_cycles_in_Xh` dacă nu rulează la ritmul așteptat.\n  /// Ex: COG, manageri proactivi (CCO, COCSA, PMA, CFO, CMA...).\n  PROACTIVE_CYCLIC\n\n  /// Agent activat la trigger extern (cerere client, alertă, audit, escaladare).\n  /// Detectorul NU raportează `no_activity_in_Xh` — absența e starea normală.\n  /// Pe viitor, va măsura latența de răspuns la triggere (dar nu acum).\n  /// Ex: DPO, CJA, CIA, CCIA, SAFETY_MONITOR, echipa L2 Suport (PSE, PSYCHOLINGUIST, PPMO, STA, SOC, SCA, PPA).\n  REACTIVE_TRIGGERED\n\n  /// Agent executor care așteaptă delegare funcțională de la managerul său.\n  /// Detectorul NU raportează absența — e stare așteptată până la activarea\n  /// mecanismului de delegare (Calea 1, sprint viitor de orchestrare execuție).\n  /// Ex: ACA, BCA, BDA, FDA, MAA, QAA, SQA etc. (agenți operaționali executori).\n  DORMANT_UNTIL_DELEGATED\n\n  /// Agent cu comportament mixt (are cicluri proprii DAR și răspunde la triggere).\n  /// Detectorul aplică ambele verificări; rezerva pentru cazuri speciale.\n  /// Ex: SOA (are cicluri proprii de prospecting ȘI răspunde la lead-uri primite).\n  HYBRID\n\n  /// Agent pauzat explicit de Owner până la rezolvarea unui gap cunoscut.\n  /// Endpoint-ul /agents/cycle NU rulează ciclul lui. Detectorul NU raportează.\n  /// Motivul trebuie documentat în memorie (ce gap, când se reia).\n  /// Ex: EMA/CCO/QLA pauzați 05.04.2026 pending Calea 1 (delegare executor).\n  PAUSED_KNOWN_GAP\n}\n\nenum RelationType {\n  REPORTS_TO\n  COLLABORATES_WITH\n}\n\nenum ProposalType {\n  ADD_AGENT\n  REMOVE_AGENT\n  MERGE_AGENTS\n  MODIFY_HIERARCHY\n  MODIFY_OBJECTIVES\n  MODIFY_PROPAGATION\n}\n\nenum ProposalStatus {\n  DRAFT\n  PROPOSED\n  COG_REVIEWED\n  OWNER_PENDING\n  APPROVED\n  REJECTED\n  EXECUTING\n  EXECUTED\n  ROLLED_BACK\n}\n\nenum OwnerDecision {\n  APPROVED\n  REJECTED\n  DEFERRED\n}\n\n// ── Brainstorming ────────────────────────────────────────────────────────────\n\nmodel BrainstormSession {\n  id               String           @id @default(cuid())\n  initiatedBy      String // agentRole care a inițiat\n  level            AgentLevel // OPERATIONAL, TACTICAL, STRATEGIC\n  topic            String           @db.Text // problema/obiectivul de rezolvat\n  context          String?          @db.Text // context adițional (obiective, constrângeri)\n  status           BrainstormStatus @default(GENERATING)\n  participantRoles String[] // agenții care participă\n\n  // Agregare\n  aggregatedFromId String? // dacă e sesiune agregată, ID-ul sesiunii sursă\n  aggregatedToId   String? // dacă a fost agregată într-o sesiune superioară\n  proposalId       String? // OrgProposal generat (dacă există)\n\n  createdAt   DateTime  @default(now())\n  completedAt DateTime?\n\n  ideas BrainstormIdea[]\n\n  @@index([initiatedBy, status])\n  @@index([level, status])\n  @@map(\"brainstorm_sessions\")\n}\n\nmodel BrainstormIdea {\n  id          String  @id @default(cuid())\n  sessionId   String\n  generatedBy String // agentRole care a generat ideea\n  title       String\n  description String  @db.Text\n  category    String? // feature, process, restructure, tool, etc.\n\n  // Scoruri pe 6 criterii (0-100)\n  viability   Float? // viabilitate implementare\n  alignment   Float? // aliniere cu obiectivele\n  marketFit   Float? // oportunitate de piață\n  costBenefit Float? // raport cost/beneficii\n  easeOfImpl  Float? // ușurință implementare\n  timeToValue Float? // rapiditate (time-to-value)\n\n  // Scor agregat (media ponderată)\n  compositeScore   Float?\n  rank             Int? // poziția în sesiune\n  scoringRationale String? @db.Text // explicația AI a scorurilor\n\n  // Status\n  status          IdeaStatus @default(PROPOSED)\n  promotedToLevel String? // dacă a fost promovată la nivel superior\n\n  createdAt DateTime @default(now())\n\n  session BrainstormSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  @@index([sessionId, compositeScore])\n  @@index([generatedBy])\n  @@map(\"brainstorm_ideas\")\n}\n\nenum BrainstormStatus {\n  GENERATING // se generează idei\n  EVALUATING // se evaluează/scorează\n  EVALUATED // scorare completă\n  AGGREGATING // se agregează la nivel superior\n  AGGREGATED // trimisă la nivel superior\n  OWNER_REVIEW // la Owner pentru decizie\n  CLOSED // finalizată\n}\n\nenum IdeaStatus {\n  PROPOSED // generată\n  SCORED // evaluată pe criterii\n  SHORTLISTED // selectată pentru nivel superior\n  PROMOTED // promovată la nivel superior\n  APPROVED // aprobată de Owner\n  REJECTED // respinsă\n  IMPLEMENTED // implementată (legată de OrgProposal)\n}\n\n// ── Client Memory (relație personalizată per client) ─────────────────────────\n\nmodel ClientMemory {\n  id         String               @id @default(cuid())\n  tenantId   String // clientul (Tenant)\n  category   ClientMemoryCategory\n  content    String               @db.Text // ce s-a observat/învățat\n  source     String // agentRole care a generat\n  importance Float                @default(0.5) // 0-1, cât de relevant e\n  tags       String[]\n  expiresAt  DateTime? // unele memorii expiră (ex: \"e în vacanță\")\n  createdAt  DateTime             @default(now())\n  updatedAt  DateTime             @updatedAt\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId, category])\n  @@index([tenantId, importance])\n  @@map(\"client_memories\")\n}\n\n// ── External Resources (dependențe Owner) ────────────────────────────────────\n\nmodel ExternalResource {\n  id       String           @id @default(cuid())\n  name     String // \"Anthropic API\", \"Neon.tech DB\", \"Domeniu jobgrade.ro\"\n  category ResourceCategory\n  provider String // \"Anthropic\", \"Neon.tech\", \"Namecheap\"\n  status   ResourceStatus   @default(ACTIVE)\n\n  // Cost & billing\n  monthlyCost     Float? // EUR\n  billingCycle    String? // \"monthly\", \"annual\"\n  nextPaymentDate DateTime?\n\n  // Expiry & renewal\n  expiresAt       DateTime? // când expiră (domeniu, certificat, API key)\n  alertDaysBefore Int       @default(14) // cu câte zile înainte alertăm\n\n  // Status\n  lastCheckedAt DateTime?\n  notes         String?   @db.Text\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([status])\n  @@index([nextPaymentDate])\n  @@map(\"external_resources\")\n}\n\nenum ResourceCategory {\n  API_SERVICE // Anthropic, Resend, Stripe\n  INFRASTRUCTURE // Neon.tech, Vercel, Docker\n  DOMAIN // jobgrade.ro\n  CERTIFICATE // SSL\n  SUBSCRIPTION // n8n cloud, monitoring\n  LICENSE // software licenses\n  OTHER\n}\n\nenum ResourceStatus {\n  ACTIVE\n  EXPIRING_SOON // < alertDaysBefore\n  EXPIRED\n  SUSPENDED\n  CANCELLED\n}\n\nenum ClientMemoryCategory {\n  PREFERENCE // cum preferă să comunice, ce formate vrea\n  RELATIONSHIP // cine e contactul principal, decidentul, influencerul\n  CONTEXT // restructurare, M&A, sezon de buget, etc.\n  PAIN_POINT // nemulțumiri, frustrări, probleme recurente\n  OPPORTUNITY // upsell, cross-sell, expansiune\n  HISTORY // ce s-a discutat, ce s-a promis, ce s-a livrat\n  STYLE // formal/informal, detaliat/sumar, RO/EN\n}\n\n// ─────────────────────────────────────────\n// PAYROLL IMPORT — Stat de plată (21 câmpuri)\n// ─────────────────────────────────────────\n\nmodel PayrollEntry {\n  id            String @id @default(cuid())\n  tenantId      String\n  importBatchId String // grup de import (un upload = un batch)\n\n  // Identificare post\n  jobCode        String // cod post intern companie\n  jobTitle       String // denumire post\n  department     String // departament\n  hierarchyLevel String // N, N-1, N-2, N-3, N-4, N-5+\n  jobFamily      String // familie posturi (Financiar, IT, Vânzări)\n\n  // Grad/Clasă — dual: calculat + evaluat\n  gradeCalculated Int? // grad auto-calculat din clustering\n  gradeEvaluated  Int? // grad din evaluare 6 criterii (după JE)\n\n  // Remunerație completă\n  baseSalary        Float // salariu bază brut RON/lună\n  fixedAllowances   Float @default(0) // sporuri fixe RON/lună\n  annualBonuses     Float @default(0) // bonusuri/prime RON/an\n  annualCommissions Float @default(0) // comisioane RON/an\n  benefitsInKind    Float @default(0) // beneficii natură RON echiv/lună\n  mealVouchers      Float @default(0) // tichete masă/vacanță RON/lună\n\n  // Date angajat (anonimizate — fără nume/CNP)\n  gender         Gender // MALE / FEMALE\n  workSchedule   WorkSchedule // 2h, 4h, 6h, 8h\n  contractType   ContractType // CIM determinat/nedeterminat/convenție\n  tenureOrg      Float        @default(0) // vechime organizație (ani)\n  tenureRole     Float        @default(0) // vechime post (ani)\n  workLocation   WorkLocation // sediu/remote/hibrid\n  city           String // localitate\n  education      Education // studii\n  certifications String? // certificări/atestări profesionale\n\n  // Calculat automat\n  totalMonthlyGross Float? // salariu total lunar brut (normalizat la 8h)\n  salaryQuartile    Int? // cuartila 1-4\n\n  // Metadata\n  createdAt  DateTime @default(now())\n  importedAt DateTime @default(now())\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId, importBatchId])\n  @@index([tenantId, jobFamily])\n  @@index([tenantId, gender])\n  @@index([tenantId, hierarchyLevel])\n}\n\nmodel PayrollImportBatch {\n  id          String   @id @default(cuid())\n  tenantId    String\n  fileName    String\n  totalRows   Int\n  validRows   Int\n  invalidRows Int      @default(0)\n  errors      Json?\n  status      String   @default(\"COMPLETED\") // COMPLETED, PARTIAL, FAILED\n  createdAt   DateTime @default(now())\n\n  tenant Tenant @relation(fields: [tenantId], references: [id], onDelete: Cascade)\n\n  @@index([tenantId])\n}\n\n// Mapare 6 criterii JobGrade → 4 criterii Lege\nmodel CriteriaMapping {\n  id             String         @id @default(cuid())\n  legalCriterion LegalCriterion\n  jobgradeFactor String // Knowledge, Communications, etc.\n  description    String\n\n  @@unique([legalCriterion, jobgradeFactor])\n}\n\nenum WorkSchedule {\n  H2 // 2 ore/zi\n  H4 // 4 ore/zi\n  H6 // 6 ore/zi\n  H8 // 8 ore/zi (norma întreagă)\n}\n\nenum ContractType {\n  CIM_NEDETERMINAT // contract pe durată nedeterminată\n  CIM_DETERMINAT // contract pe durată determinată\n  CONVENTIE // convenție civilă\n}\n\nenum WorkLocation {\n  SEDIU\n  REMOTE\n  HIBRID\n}\n\nenum Education {\n  MEDII // studii medii / liceu\n  SUPERIOARE // licență\n  MASTER // master\n  DOCTORAT // doctorat\n}\n\nenum LegalCriterion {\n  CUNOSTINTE_DEPRINDERI // Knowledge + Communications\n  EFORT_INTELECTUAL_FIZIC // Problem Solving\n  RESPONSABILITATI // Decision Making + Business Impact\n  CONDITII_MUNCA // Working Conditions\n}\n\n// ─────────────────────────────────────────\n// SALARY BENCHMARK — Date piață salarială\n// ─────────────────────────────────────────\n\nmodel SalaryBenchmark {\n  id           String          @id @default(cuid())\n  source       BenchmarkSource\n  sourceDetail String? // \"INS 2025 Q4\", \"Glassdoor Jan 2026\"\n  year         Int // anul datelor\n  quarter      Int? // Q1-Q4 (opțional)\n  country      String          @default(\"RO\") // ISO 3166-1 alpha-2\n\n  // Identificare ocupație\n  jobFamily      String // \"IT\", \"Financiar\", \"Vanzari\", \"HR\", etc.\n  jobTitle       String? // titlu specific (opțional)\n  corCode        String? // Cod COR (Clasificarea Ocupatiilor din Romania)\n  iscoCode       String? // Cod ISCO-08 (international)\n  seniorityLevel SeniorityLevel // ENTRY, MID, SENIOR, LEAD, EXECUTIVE\n\n  // Grade mapping — legătura cu sistemul intern JobGrade\n  gradeMin Int? // gradul minim echivalent (1-8)\n  gradeMax Int? // gradul maxim echivalent (1-8)\n\n  // Date salariale (brut lunar RON)\n  salaryP10    Float? // percentila 10\n  salaryP25    Float // percentila 25 (Q1)\n  salaryMedian Float // mediana (P50)\n  salaryP75    Float // percentila 75 (Q3)\n  salaryP90    Float? // percentila 90\n  salaryMean   Float? // media aritmetică\n  sampleSize   Int? // dimensiune eșantion\n\n  // Metadata\n  region   String? // \"București\", \"Transilvania\", \"National\"\n  industry String? // \"IT&C\", \"Banking\", \"Manufacturing\"\n  currency String  @default(\"RON\")\n  notes    String? @db.Text\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([jobFamily, seniorityLevel, year])\n  @@index([country, year, quarter])\n  @@index([gradeMin, gradeMax])\n  @@index([corCode])\n  @@map(\"salary_benchmarks\")\n}\n\nenum BenchmarkSource {\n  INS_TEMPO // Institutul Național de Statistică — baza TEMPO online\n  EUROSTAT // Eurostat Structure of Earnings Survey\n  GLASSDOOR // Glassdoor salary data (public)\n  UNDELUCRAM // Undelucram.ro salary reports\n  BESTJOBS // BestJobs salary index\n  HAYS // Hays Salary Guide Romania\n  PWCRO // PwC PayWell Romania\n  KPMGRO // KPMG Salary Survey\n  MERCER // Mercer Total Remuneration Survey\n  CUSTOM // Date proprii / import manual\n}\n\nenum SeniorityLevel {\n  ENTRY // 0-2 ani experiență\n  MID // 2-5 ani\n  SENIOR // 5-10 ani\n  LEAD // 10+ ani, conducere echipă\n  EXECUTIVE // C-level, director\n}\n\n// ── Dialog-Centric Engine ──────────────────────────────────────────────────\n\n/// Conversation thread — persistent chat history (COG, Team, Assistant)\nmodel ConversationThread {\n  id          String     @id @default(cuid())\n  tenantId    String\n  userId      String\n  agentRole   String // COG, HR_COUNSELOR, MEDIATOR, etc.\n  threadType  ThreadType @default(ASSISTANT)\n  title       String? // Auto-generated summary\n  pageContext String? // Page where conversation started\n  isActive    Boolean    @default(true)\n  createdAt   DateTime   @default(now())\n  updatedAt   DateTime   @updatedAt\n\n  messages ConversationMessage[]\n\n  @@index([tenantId, userId, isActive])\n  @@index([userId, agentRole])\n  @@map(\"conversation_threads\")\n}\n\n/// Single message in a conversation thread\nmodel ConversationMessage {\n  id        String      @id @default(cuid())\n  threadId  String\n  role      MessageRole\n  content   String      @db.Text\n  metadata  Json? // flags, suggestions, internal notes\n  createdAt DateTime    @default(now())\n\n  thread ConversationThread @relation(fields: [threadId], references: [id], onDelete: Cascade)\n\n  @@index([threadId, createdAt])\n  @@map(\"conversation_messages\")\n}\n\n/// User interaction log — tracks everything for context building\nmodel InteractionLog {\n  id         String          @id @default(cuid())\n  tenantId   String\n  userId     String\n  eventType  InteractionType\n  pageRoute  String? // /jobs, /sessions/[id], etc.\n  entityType String? // job, session, report, document\n  entityId   String? // ID of the entity interacted with\n  detail     String? // search query, button clicked, etc.\n  durationMs Int? // time spent on page/action\n  createdAt  DateTime        @default(now())\n\n  @@index([tenantId, userId, createdAt])\n  @@index([userId, eventType])\n  @@index([tenantId, entityType, entityId])\n  @@map(\"interaction_logs\")\n}\n\nenum ThreadType {\n  COG_CHAT // Owner ↔ COG\n  TEAM_CHAT // Owner ↔ any agent\n  ASSISTANT // Contextual assistant (any user)\n  HR_COUNSELOR // B2B HR interface\n  B2C_GUIDE // B2C Călăuza (Card 1)\n  B2C_PROFILER // B2C Profiler (Card 6)\n  B2C_CAREER // B2C Consilier Carieră (Card 3)\n  B2C_RELATIONS // B2C Consilier Dezvoltare Personală (Card 2)\n  B2C_COACH // B2C Coach (Card 4-5)\n}\n\nenum MessageRole {\n  USER\n  ASSISTANT\n  SYSTEM\n}\n\nenum InteractionType {\n  PAGE_VIEW // User visited a page\n  PAGE_LEAVE // User left a page (with duration)\n  FEATURE_USE // Used a specific feature (AI generate, export, etc.)\n  DOCUMENT_VIEW // Viewed a document\n  DOCUMENT_DOWNLOAD // Downloaded a document/report\n  REPORT_GENERATE // Generated a report\n  SEARCH // Searched for something\n  EVALUATION_START // Started evaluating a job\n  EVALUATION_SUBMIT // Submitted an evaluation\n  SESSION_JOIN // Joined a session\n  CHAT_START // Started a conversation\n  CHAT_MESSAGE // Sent a message\n  SETTINGS_CHANGE // Changed a setting\n  HELP_REQUEST // Clicked help / opened assistant\n}\n\n// ─────────────────────────────────────────\n// DISFUNCTION DETECTION (functional-only, per principle 05.04.2026)\n// Scope: canale / ritm / tranziții. NICIODATĂ conținut semantic.\n// ─────────────────────────────────────────\n\nmodel DisfunctionEvent {\n  id String @id @default(cuid())\n\n  // Clasificare\n  class    DisfunctionClass // D1 tehnic / D2 funcțional managerial / D3 proces business\n  severity DisfunctionSeverity @default(MEDIUM)\n  status   DisfunctionStatus   @default(OPEN)\n\n  // Subiect (ce e afectat) — metadata pură, zero conținut\n  targetType DisfunctionTarget // SERVICE / WORKFLOW / ROLE / FLUX_STEP\n  targetId   String // ex: \"nextjs-app\", \"FLUX-024\", \"COG\", \"FLUX-001:step3\"\n\n  // Detecție\n  detectorSource String // ex: \"FLUX-041-healthcheck\", \"metric-diversity\", \"flux-sla-monitor\"\n  detectedAt     DateTime @default(now())\n  signal         String // etichetă scurtă: \"ECONNREFUSED\", \"cycle_missed_24h\", \"sla_exceeded_2x\"\n  durationMs     Int? // cât timp e în disfuncție (dacă aplicabil)\n\n  // Remediere\n  remediationLevel  RemediationLevel? // AUTO / AGENT / OWNER\n  remediationAction String? // etichetă acțiune: \"restart\", \"retry\", \"re-trigger\", \"notify\"\n  remediationAt     DateTime?\n  remediationOk     Boolean?\n\n  // Închidere\n  resolvedAt DateTime?\n  resolvedBy String? // ex: \"auto\", \"SA\", \"COG\", \"owner\"\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([class, status])\n  @@index([targetType, targetId])\n  @@index([detectedAt])\n  @@map(\"disfunction_events\")\n}\n\nenum DisfunctionClass {\n  D1_TECHNICAL // Infrastructură / servicii / workflow-uri\n  D2_FUNCTIONAL_MGMT // Rol care nu execută funcțiile sale\n  D3_BUSINESS_PROCESS // Flux business blocat / oprit / în buclă\n}\n\nenum DisfunctionSeverity {\n  LOW\n  MEDIUM\n  HIGH\n  CRITICAL\n}\n\nenum DisfunctionStatus {\n  OPEN\n  REMEDIATING\n  RESOLVED\n  ESCALATED\n}\n\nenum DisfunctionTarget {\n  SERVICE // infra: Next.js, Postgres, Redis, n8n etc.\n  WORKFLOW // n8n workflow: FLUX-XXX\n  ROLE // rol organigramă: COG, CFO, CCO, etc.\n  FLUX_STEP // pas specific într-un flux business\n}\n\nenum RemediationLevel {\n  AUTO // Nivel 1: idempotent, reversibil (restart, retry, re-trigger)\n  AGENT // Nivel 2: agent responsabil preia sarcina\n  OWNER // Nivel 3: escaladare la Owner\n}\n\n// ─────────────────────────────────────────\n// FLUX ↔ ROLE MAPPING (Sprint 3 Faza 3b, 05.04.2026)\n// Mapează pașii din fluxurile business la rolurile care îi dețin.\n// Folosit pentru:\n//  - când un rol e D2, găsim fluxurile afectate (/related)\n//  - când un flux e D3 la un pas, escalăm la managerul rolului care deține pasul\n// Principiu: metadata pură a proprietății funcționale, zero conținut semantic.\n// ─────────────────────────────────────────\n\nmodel FluxStepRole {\n  id         String  @id @default(cuid())\n  fluxId     String // ex: \"FLUX-001-job-evaluation\"\n  stepId     String // ex: \"score_committee\" | \"approve_structure\"\n  roleCode   String // agentRole din AgentDefinition (nu FK — poate include roluri umane viitoare)\n  raci       String // OWNER | CONTRIBUTOR | REVIEWER | NOTIFIED\n  slaMinutes Int? // cât timp e permis rolului să țină pasul\n  isCritical Boolean @default(false) // single point of failure\n  notes      String? @db.Text\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([fluxId, stepId, roleCode, raci])\n  @@index([fluxId])\n  @@index([roleCode])\n  @@map(\"flux_step_roles\")\n}\n\n// ─────────────────────────────────────────\n// WORKFLOW ENGINE — instanțe de proces la runtime\n// ─────────────────────────────────────────\n\nmodel ProcessInstance {\n  id          String        @id @default(cuid())\n  businessId  String\n  fluxId      String // referință la FluxStepRole.fluxId\n  name        String // \"Evaluare posturi Q2 2026\"\n  status      ProcessStatus @default(RUNNING)\n  triggeredBy String // agentRole sau \"OWNER\"\n  currentStep String? // stepId curent activ\n  context     Json? // date partajate între pași\n  startedAt   DateTime      @default(now())\n  completedAt DateTime?\n  failedAt    DateTime?\n  failReason  String?       @db.Text\n\n  steps ProcessStepInstance[]\n\n  @@index([businessId, fluxId])\n  @@index([status])\n  @@map(\"process_instances\")\n}\n\nmodel ProcessStepInstance {\n  id            String     @id @default(cuid())\n  processId     String\n  stepId        String // din FluxStepRole.stepId\n  assignedTo    String // agentRole OWNER din RACI\n  status        StepStatus @default(PENDING)\n  input         Json? // output-ul pasului anterior\n  output        Json? // ce produce acest pas\n  taskId        String? // AgentTask creat pentru execuție\n  slaDeadline   DateTime? // calculat din slaMinutes\n  startedAt     DateTime?\n  completedAt   DateTime?\n  failedAt      DateTime?\n  failReason    String?    @db.Text\n  reviewedBy    String?\n  reviewQuality Int? // 0-100\n\n  process ProcessInstance @relation(fields: [processId], references: [id], onDelete: Cascade)\n\n  @@index([processId, stepId])\n  @@index([status])\n  @@map(\"process_step_instances\")\n}\n\nenum ProcessStatus {\n  RUNNING\n  COMPLETED\n  FAILED\n  PAUSED\n  CANCELLED\n}\n\nenum StepStatus {\n  PENDING // așteaptă pasul anterior\n  READY // poate fi executat\n  IN_PROGRESS // se execută\n  COMPLETED // terminat cu succes\n  FAILED // eșuat\n  SKIPPED // sărit (opțional)\n  BLOCKED // blocat de dependență\n}\n\n// ─────────────────────────────────────────\n// REORGANIZATION EVENTS (Sprint 3 Faza 3c, schema stub 05.04.2026)\n// Înregistrează reorganizările temporare auto-aplicate de sistem când un rol e D2.\n// Sunt TOATE reversibile automat la pragul configurat (default 24h).\n// Dacă se repetă ≥3 ori pe același rol în 30 zile → propunere schimbare permanentă.\n// Principiu: atingem DOAR structura temporară (canal, nu fond). KB rămâne neatins.\n// ─────────────────────────────────────────\n\nmodel ReorganizationEvent {\n  id String @id @default(cuid())\n\n  // Subiect: rolul D2 care a declanșat reorganizarea\n  triggeredByRole    String // ex: \"CCO\"\n  triggeredByEventId String? // DisfunctionEvent.id care a cauzat\n\n  // Tipul reorganizării\n  reorgType ReorganizationType\n\n  // Configurația înainte vs după (JSON pentru flexibilitate)\n  // originalConfig: snapshot înainte (pentru revert)\n  // newConfig: snapshot după reorganizare\n  originalConfig Json\n  newConfig      Json\n\n  // Ciclul de viață\n  status       ReorgStatus @default(ACTIVE)\n  appliedAt    DateTime    @default(now())\n  autoRevertAt DateTime // momentul automat de revert (default +24h)\n  revertedAt   DateTime?\n  revertReason String? // \"auto_timeout\" | \"role_recovered\" | \"owner_override\" | \"conflict\"\n\n  // Pattern detection (pentru StructuralChangeProposal)\n  // Semnalat true când aceeași reorganizare s-a aplicat ≥3 ori în 30 zile.\n  isRepeatedPattern Boolean @default(false)\n  patternSignature  String? // hash stabil pt detectarea pattern-ului\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([triggeredByRole, status])\n  @@index([status, autoRevertAt])\n  @@index([patternSignature])\n  @@map(\"reorganization_events\")\n}\n\nenum ReorganizationType {\n  SUBORDINATE_REASSIGN // subordonați mutați temporar la peer\n  TASK_REASSIGN // task specific re-asignat la peer\n  ROLE_COLLAPSE // rol absorbit temporar în părinte\n  PEER_PROMOTION // peer preia atribuțiile rolului D2\n}\n\nenum ReorgStatus {\n  ACTIVE // în curs, reorganizarea e aplicată\n  REVERTED // revocată automat sau manual\n  ESCALATED // persistă >72h → escaladat la Owner pentru decizie permanentă\n  CONFLICTED // peer e și el D2 → nu se poate executa\n}\n\n// ─────────────────────────────────────────\n// BUSINESS — top-level organism (Increment A0 \"Living Organization\", 05.04.2026)\n//\n// Reprezintă un \"organism viu\" complet — un business de sine-stătător cu propriile\n// obiective, granițe, homeostazie, ciclu de viață. JobGrade e Business #1, viitorul\n// Business #2 (antreprenoriat transformațional) e al doilea organism care va\n// coexista și sinergiza cu primul.\n//\n// Awareness layer (ExternalSignal, EmergentTheme, StrategicTheme) e PARTAJAT\n// între businesses. Totul de la Goals în sus (A-G) e scoped per Business prin FK.\n//\n// Vezi project_living_org_architecture.md pentru arhitectura completă.\n// ─────────────────────────────────────────\n\nmodel Business {\n  id             String                 @id @default(cuid())\n  code           String                 @unique // ex: \"jobgrade\", \"b2-antreprenoriat\"\n  name           String // display name\n  description    String?                @db.Text\n  status         BusinessStatus         @default(ACTIVE)\n  lifecyclePhase BusinessLifecyclePhase @default(GROWTH) // folosit de E3 Lifecycle\n  mvvStatement   String?                @db.Text // linkback la identitate/purpose\n  createdAt      DateTime               @default(now())\n  updatedAt      DateTime               @updatedAt\n\n  @@index([status])\n  @@map(\"businesses\")\n}\n\nenum BusinessStatus {\n  PRE_LAUNCH // în construcție\n  PILOT // testare cu clienți limitați\n  ACTIVE // operațional full\n  CONSOLIDATING // pauză de creștere, rafinare internă\n  SUSPENDED // pauză temporară\n  ARCHIVED // oprit permanent\n}\n\nenum BusinessLifecyclePhase {\n  GROWTH // expansiune, mai multă brainstorming, toleranță mare la experiment\n  MATURE // execuție, stabilitate, eficiență\n  CONSOLIDATION // rafinare, prunning, eliminare risipă\n  PIVOT // schimbare direcție majoră, re-explorare\n}\n\n// ─────────────────────────────────────────\n// ORGANIZATIONAL OBJECTIVES (Increment A1 \"Living Organization\", 05.04.2026)\n//\n// Obiectivele operaționale ale organismului — ce vrea să atingă Business-ul, cum\n// se măsoară, până când, cu ce prioritate. Fundament pentru tot ce urmează:\n//  - ObjectiveHealth (A2) calculează sănătatea fiecăruia\n//  - AgentBehaviorPatch (B1) poate fi triggered când un obiectiv devine AT_RISK\n//  - HomeostaticTarget (C1) se leagă la obiective\n//  - ResourceBudget (E2) se alocă în funcție de priority + health\n//\n// Fiecare obiectiv e scoped la un Business specific. Awareness layer e shared\n// între businesses, dar obiectivele sunt individuale.\n//\n// Vezi project_living_org_architecture.md pentru context complet.\n// ─────────────────────────────────────────\n\nmodel OrganizationalObjective {\n  id         String @id @default(cuid())\n  businessId String // FK la Business — scope fundamental\n\n  // Identitate\n  code        String // slug intern, unic per business\n  title       String // titlu uman scurt\n  description String @db.Text\n\n  // Metric de succes\n  metricName   String // ex: \"clienti_b2b_activi\", \"nps_b2c\", \"kb_validity_avg\"\n  metricUnit   String? // ex: \"numar\", \"%\", \"zile\"\n  targetValue  Float // valoarea țintă\n  currentValue Float? // ultima măsurătoare cunoscută (opțional — poate fi calculată din surse)\n  direction    ObjectiveDirection @default(INCREASE) // țintim creștere sau scădere\n\n  // Timing\n  startDate   DateTime  @default(now())\n  deadlineAt  DateTime? // opțional — unele obiective sunt continue\n  completedAt DateTime?\n\n  // Prioritate & Status\n  priority ObjectivePriority @default(MEDIUM)\n  status   ObjectiveStatus   @default(ACTIVE)\n\n  // Relații la rolurile responsabile (agenți / departamente)\n  // Nu FK strict — agentRole e string, pentru compatibilitate cu AgentDefinition\n  ownerRoles       String[] @default([]) // ex: [\"COCSA\", \"CCO\"]\n  contributorRoles String[] @default([]) // ex: [\"MKA\", \"SOA\"]\n\n  // Context / tags pentru pattern matching (folosit de A2 ObjectiveHealth)\n  tags String[] @default([]) // ex: [\"b2b\", \"growth\", \"sales\"]\n\n  // Linkback la surse (opțional — unele obiective au documente asociate)\n  sourceDocUrl String?\n\n  // ── Cascadă ierarhică (adăugat pentru COG top-down decomposition) ────────\n  // Obiectiv părinte din care a fost derivat (null = top-level strategic)\n  parentObjectiveId String?\n  // Nivel organizațional\n  level             ObjectiveLevel @default(STRATEGIC)\n  // Cine a creat cascada (null = manual/owner, \"COG\" = auto-propus de COG)\n  cascadedBy        String? // \"COG\" | \"owner\" | agentRole\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  createdBy String? // \"owner\" | agentRole | userId\n\n  @@unique([businessId, code])\n  @@index([businessId, status])\n  @@index([businessId, priority])\n  @@index([deadlineAt])\n  @@index([parentObjectiveId])\n  @@map(\"organizational_objectives\")\n}\n\nenum ObjectiveLevel {\n  STRATEGIC // Owner — direcție de business\n  TACTICAL // Department head — descompunere pe funcții\n  OPERATIONAL // Executor — metrica concretă, zilnică\n}\n\nenum ObjectiveDirection {\n  INCREASE // țintim valoare MAI MARE (ex: nr clienți, satisfacție)\n  DECREASE // țintim valoare MAI MICĂ (ex: churn, latency, cost)\n  MAINTAIN // menținem într-o bandă (ex: KB validity în [80%, 95%])\n  REACH // atingem o valoare specifică o dată (ex: lansare în 30 zile)\n}\n\nenum ObjectivePriority {\n  CRITICAL // blocker existențial, orice sub-optim e roșu\n  HIGH\n  MEDIUM\n  LOW // nice-to-have, rareori cere acțiune\n}\n\nenum ObjectiveStatus {\n  DRAFT // în lucru, nu e încă activ\n  ACTIVE // urmărit activ\n  AT_RISK // deviere semnificativă față de traiectorie — cere atenție\n  MET // atins\n  FAILED // termenul a expirat fără atingere\n  SUSPENDED // pauză temporară\n  ARCHIVED // închis permanent (fără succes/eșec)\n}\n\n// ─────────────────────────────────────────\n// EXTERNAL SIGNALS (Increment #1 \"Living Organization\" roadmap, 05.04.2026)\n// Ochi spre mediul extern: ingerăm semnale brute din surse externe (RSS, API-uri\n// publice, feed-uri legal/piață) și le păstrăm normalizat pentru ca observatorul\n// strategic (COSO, Increment #3) să le interpreteze ulterior.\n// Principiu: acest strat e doar INGESTIE + NORMALIZARE. Zero interpretare aici.\n// ─────────────────────────────────────────\n\nmodel ExternalSignal {\n  id String @id @default(cuid())\n\n  // Sursa\n  source    String // ex: \"wall-street.ro\", \"eur-lex.europa.eu\"\n  sourceUrl String // URL direct la articol/document\n  category  ExternalSignalCategory\n\n  // Conținut (raw — aggregatorul strategic îl consumă ulterior)\n  title      String @db.Text\n  rawContent String @db.Text\n\n  // Timing\n  capturedAt  DateTime  @default(now())\n  publishedAt DateTime? // data din sursă, dacă disponibilă\n\n  // Dedup: hash stabil (ex: sha1(source + sourceUrl)) setat de ingestor.\n  // Upsert pe acest câmp → rulări repetate sunt idempotente.\n  fingerprint String @unique\n\n  // Populat de COSO (Increment #3) după procesare strategică.\n  // Null = încă neprocesat; setat = deja interpretat în teme.\n  processedAt DateTime?\n  themes      String[]  @default([])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([category, capturedAt])\n  @@index([processedAt])\n  @@index([source, capturedAt])\n  @@map(\"external_signals\")\n}\n\nenum ExternalSignalCategory {\n  MARKET_HR // Piața muncii, HR, salarii, tendințe recrutare\n  LEGAL_REG // Legislativ / reglementar (extinde monitorizarea existentă)\n  TECH_AI // Tehnologii, AI, platforme relevante\n  CULTURAL_SOCIAL // Schimbări culturale, demografice, comportamentale\n  COMPETITOR // Mișcări ale jucătorilor adiacenți / concurență\n  MACRO_ECONOMIC // Indicatori macro RO / EU\n}\n\n// ─────────────────────────────────────────\n// AGENT BEHAVIOR PATCHES (Increment B1 \"Living Organization\", 06.04.2026)\n//\n// Primul strat de ACȚIUNE — sistemul nu doar observă ci propune schimbări\n// reversibile pe comportamentul agenților. Fiecare patch:\n//  - E PROPUS (de COSO, ObjectiveHealth, sau manual) → Owner aprobă\n//  - Se APLICĂ pe un agent specific (schimbă config temporar)\n//  - Se AUTO-REVERT-EAZĂ la expirare (default 24h) dacă nu e CONFIRMAT\n//  - Are AUDIT TRAIL complet (cine, de ce, când, ce s-a schimbat)\n//\n// patchSpec e JSON flexibil — fiecare patchType are structură proprie.\n// Exemplu PRIORITY_SHIFT: { \"from\": \"MEDIUM\", \"to\": \"CRITICAL\", \"context\": \"...\" }\n// Exemplu ACTIVITY_MODE: { \"from\": \"DORMANT_UNTIL_DELEGATED\", \"to\": \"PROACTIVE_CYCLIC\" }\n// Exemplu CYCLE_INTERVAL: { \"from\": 24, \"to\": 4 }\n//\n// Relație cu alte straturi:\n//  - COSO (#3) propune patches când StrategicTheme.confidence=HIGH\n//  - ObjectiveHealth (A2) propune patches când objective.riskLevel=CRITICAL/HIGH\n//  - C2 Self-regulation refolosește acest mecanism pentru corecții automate\n// ─────────────────────────────────────────\n\nmodel AgentBehaviorPatch {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Agent afectat\n  targetRole String // agentRole din AgentDefinition\n\n  // Ce se schimbă\n  patchType PatchType\n  patchSpec Json // config type-specific (structură variabilă per patchType)\n\n  // De ce (audit trail complet)\n  triggeredBy     String // \"owner\" | \"COSO\" | \"ObjectiveHealth\" | \"Homeostasis\" | agentRole\n  triggerSourceId String? // ID-ul sursei: StrategicTheme.id, ObjectiveHealthReport.objectiveId, etc.\n  rationale       String  @db.Text\n\n  // Ciclu de viață\n  status       PatchStatus @default(PROPOSED)\n  appliedAt    DateTime?\n  expiresAt    DateTime? // auto-revert la acest moment (null = fără expirare, necesită confirm/revert manual)\n  confirmedAt  DateTime? // Owner confirmă → nu mai expiră automat\n  revertedAt   DateTime?\n  revertReason String? // \"auto_expired\" | \"owner_reverted\" | \"owner_rejected\" | \"superseded\"\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([businessId, status])\n  @@index([targetRole, status])\n  @@index([expiresAt])\n  @@map(\"agent_behavior_patches\")\n}\n\nenum PatchType {\n  PRIORITY_SHIFT // schimbă prioritatea de focus a agentului\n  ATTENTION_SHIFT // redirecționează atenția pe tags/topics specifice\n  SCOPE_EXPAND // adaugă temporar responsabilități\n  SCOPE_NARROW // reduce temporar responsabilități\n  ACTIVITY_MODE // schimbă activityMode (ex: DORMANT → PROACTIVE)\n  CYCLE_INTERVAL // schimbă frecvența ciclului (ex: 24h → 4h)\n}\n\nenum PatchStatus {\n  PROPOSED // propus de COSO/ObjectiveHealth/owner, în așteptare\n  APPROVED // Owner a aprobat, nu încă aplicat\n  ACTIVE // aplicat pe agent, în vigoare\n  EXPIRED // auto-revert după timeout (expiresAt depășit)\n  CONFIRMED // Owner a confirmat permanent — nu mai expiră\n  REVERTED // revertat manual de Owner\n  REJECTED // Owner a respins propunerea\n}\n\n// ─────────────────────────────────────────\n// HOMEOSTATIC TARGETS (Increment C1 \"Living Organization\", 06.04.2026)\n//\n// Auto-reglare proactivă — menține parametrii interni ai organismului în\n// bandă sănătoasă. Diferit de disfuncții (reactive: \"s-a rupt\") — acesta\n// e proactiv: \"menții pH-ul în [7.35, 7.45], nu aștepta acidoză\".\n//\n// Fiecare target e scoped per Business, cu bandă (min, max) sau prag unic.\n// Readings se colectează periodic (cron sau la cerere) și se compară cu target.\n// Devierea produce alert + opțional propunere AgentBehaviorPatch (prin B1).\n//\n// Exemple concrete:\n//  - response_latency_p95 ≤ 2000ms (SERVICE)\n//  - kb_validity_avg ≥ 75% (SYSTEM)\n//  - agent_cycle_success_rate ≥ 90% (ROLE)\n//  - decision_throughput ≥ 3/zi (SYSTEM)\n// ─────────────────────────────────────────\n\nmodel HomeostaticTarget {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Identitate\n  code        String // slug unic per business\n  name        String // display name uman\n  description String? @db.Text\n\n  // Ce se măsoară\n  metricName     String // ex: \"response_latency_p95\", \"kb_validity_avg\"\n  metricUnit     String? // ex: \"ms\", \"%\", \"count/day\"\n  targetType     HomeostaticTargetType // SERVICE, ROLE, SYSTEM\n  targetEntityId String? // dacă e pe un serviciu/rol specific (null = system-wide)\n\n  // Bandă sănătoasă\n  minValue     Float? // sub asta = deviation LOW (dacă direcție INCREASE)\n  maxValue     Float? // peste asta = deviation HIGH (dacă direcție DECREASE)\n  optimalValue Float? // valoarea ideală (centrul benzii)\n\n  // Configurare alerte\n  warningPct  Float @default(10) // % deviere de la optimal care declanșează WARNING\n  criticalPct Float @default(25) // % deviere care declanșează CRITICAL\n\n  // Stare curentă (last reading)\n  lastReading   Float?\n  lastReadingAt DateTime?\n  currentStatus HomeostaticStatus @default(UNKNOWN)\n\n  // Auto-acțiune: dacă true, generează AgentBehaviorPatch automat la CRITICAL\n  autoCorrect Boolean @default(false)\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([businessId, code])\n  @@index([businessId, isActive])\n  @@index([currentStatus])\n  @@map(\"homeostatic_targets\")\n}\n\nenum HomeostaticTargetType {\n  SERVICE // infrastructură specifică (ex: latency Next.js)\n  ROLE // agent specific (ex: success rate CCO)\n  SYSTEM // cross-cutting (ex: KB validity medie, decision throughput)\n}\n\nenum HomeostaticStatus {\n  UNKNOWN // fără reading\n  OPTIMAL // în bandă, aproape de optimal\n  NORMAL // în bandă, ușor deviat\n  WARNING // deviat > warningPct de la optimal\n  CRITICAL // deviat > criticalPct de la optimal\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// CALEA 1 — DELEGARE MANAGER → EXECUTOR\n// ═══════════════════════════════════════════════════════════════════════════════\n//\n// Mecanismul care deblochează agenții DORMANT_UNTIL_DELEGATED.\n// Managerii creează task-uri, executorii le primesc și le execută.\n// Flow: INTERVENE → AgentTask → executor acceptă → execuție → feedback.\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel AgentTask {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Cine delegă\n  assignedBy String // managerRole care a creat task-ul\n  cycleLogId String? // legătura cu CycleLog care a generat task-ul\n\n  // Către cine\n  assignedTo String // agentRole executor\n\n  // Ce trebuie făcut\n  title       String // rezumat scurt\n  description String            @db.Text // detalii complete\n  taskType    AgentTaskType\n  priority    AgentTaskPriority @default(NECESAR)\n\n  // Context\n  objectiveId String? // legat de un OrganizationalObjective\n  tags        String[] // pentru pattern matching\n\n  // Deadline\n  deadlineAt       DateTime?\n  estimatedMinutes Int?\n\n  // Lifecycle\n  status      AgentTaskStatus @default(ASSIGNED)\n  acceptedAt  DateTime?\n  startedAt   DateTime?\n  completedAt DateTime?\n  failedAt    DateTime?\n\n  // Blocaje\n  blockerType        BlockerType? // tipul blocajului (dacă e blocat)\n  blockerDescription String?      @db.Text // descriere text liber a blocajului\n  blockerAgentRole   String? // rolul agentului/resursei care blochează\n  blockerTaskId      String? // task-ul de care depinde (dacă e dependență)\n  blockedAt          DateTime? // când a fost raportat blocajul\n  unblockedAt        DateTime? // când a fost rezolvat\n\n  // Rezultat\n  result        String? @db.Text // ce a produs executorul\n  resultQuality Int? // 0-100, evaluat de manager la review\n  failureReason String? @db.Text\n  kbHit         Boolean @default(false) // true = rezolvat din KB (știut), false = executat real (făcut)\n\n  // Feedback loop\n  reviewedBy String? // managerul care a evaluat rezultatul\n  reviewedAt DateTime?\n  reviewNote String?   @db.Text\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([businessId, assignedTo, status])\n  @@index([businessId, assignedBy, status])\n  @@index([assignedTo, status])\n  @@index([status, priority])\n  @@index([status, blockerType])\n  @@index([deadlineAt])\n  @@map(\"agent_tasks\")\n}\n\nenum AgentTaskType {\n  KB_RESEARCH // cercetare și adăugare în KB\n  KB_VALIDATION // validare entries existente\n  DATA_ANALYSIS // analiză date/metrici\n  CONTENT_CREATION // creare conținut (rapoarte, documente)\n  PROCESS_EXECUTION // execuție proces predefinit\n  REVIEW // review artefact\n  INVESTIGATION // investigare problemă/anomalie\n  OUTREACH // contactare externă (clienți, parteneri)\n}\n\nenum AgentTaskPriority {\n  IMPORTANT_URGENT // 1. Important și urgent — trebuie rezolvat ACUM\n  URGENT // 2. Urgent — presiune de timp, dar nu neapărat strategic\n  IMPORTANT // 3. Important — impact mare, dar fără presiune imediată\n  NECESAR // 4. Necesar — trebuie făcut, dar poate aștepta\n\n  // Legacy mapping (backwards compat — nu se mai folosesc la creare)\n  CRITICAL // → IMPORTANT_URGENT\n  HIGH // → URGENT\n  MEDIUM // → IMPORTANT\n  LOW // → NECESAR\n}\n\nenum AgentTaskStatus {\n  ASSIGNED // creat, în așteptare acceptare\n  ACCEPTED // executorul a confirmat\n  IN_PROGRESS // în lucru\n  BLOCKED // blocat — vezi blockerType + blockerDescription\n  COMPLETED // finalizat cu succes\n  FAILED // eșuat (cu motiv)\n  CANCELLED // anulat de manager\n  EXPIRED // deadline depășit fără completare\n  REVIEW_PENDING // completat, în așteptare review manager\n}\n\nenum BlockerType {\n  DEPENDENCY // depinde de alt task (blockerTaskId)\n  WAITING_INPUT // așteaptă input de la alt agent/rol (blockerAgentRole)\n  WAITING_OWNER // așteaptă decizie Owner\n  EXTERNAL // factor extern (furnizor, API, legislație)\n  RESOURCE // lipsă resurse (buget, credite, capacitate)\n  TECHNICAL // impediment tehnic (bug, infrastructură)\n  UNCLEAR_SCOPE // cerință neclară, necesită clarificare\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// STRATUL D — IMMUNE (granițe + carantină)\n// ═══════════════════════════════════════════════════════════════════════════════\n//\n// D1: Reguli de graniță — moral core, scope, consistency.\n//     Verifică cereri client, directive interne, date intrate.\n// D2: Carantină + memorie imună — pattern detection pe violări repetate.\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel BoundaryRule {\n  id         String  @id @default(cuid())\n  businessId String? // null = shared (moral core)\n\n  code        String           @unique // slug unic global\n  name        String\n  description String?          @db.Text\n  ruleType    BoundaryRuleType\n  severity    BoundarySeverity @default(HIGH)\n\n  // Condiție (JSON): ce pattern activează regula\n  // Ex: { \"keywords\": [\"discriminare\", \"hărțuire\"], \"context\": \"client_input\" }\n  // Ex: { \"roleScope\": \"CJA\", \"forbiddenActions\": [\"modify_salary\"] }\n  condition Json\n\n  // Acțiune la violație\n  action          BoundaryAction @default(BLOCK)\n  notifyRoles     String[] // cine primește notificare\n  escalateToOwner Boolean        @default(false)\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  violations BoundaryViolation[]\n\n  @@index([businessId, ruleType, isActive])\n  @@map(\"boundary_rules\")\n}\n\nmodel BoundaryViolation {\n  id         String       @id @default(cuid())\n  ruleId     String\n  rule       BoundaryRule @relation(fields: [ruleId], references: [id])\n  businessId String?\n\n  // Context violației\n  sourceType    String // \"client_input\" | \"agent_action\" | \"data_import\" | \"directive\"\n  sourceId      String? // ID-ul sursei (conversationId, patchId, etc.)\n  sourceRole    String? // agentul care a produs violația\n  inputSnapshot String  @db.Text // snapshot-ul care a violat regula\n\n  // Rezultat\n  actionTaken    BoundaryAction // ce s-a făcut\n  wasOverridden  Boolean        @default(false) // Owner a override-uit\n  overrideBy     String?\n  overrideReason String?        @db.Text\n\n  createdAt DateTime @default(now())\n\n  // Legătură cu carantina\n  quarantineEntry QuarantineEntry?\n\n  @@index([ruleId, createdAt])\n  @@index([businessId, createdAt])\n  @@map(\"boundary_violations\")\n}\n\nmodel QuarantineEntry {\n  id          String            @id @default(cuid())\n  violationId String            @unique\n  violation   BoundaryViolation @relation(fields: [violationId], references: [id])\n  businessId  String?\n\n  // Ce e în carantină\n  contentType String // \"message\" | \"file\" | \"data_row\" | \"directive\"\n  contentHash String // fingerprint pentru dedup\n  content     String @db.Text // conținutul izolat\n\n  // Status\n  status        QuarantineStatus @default(QUARANTINED)\n  reviewedBy    String? // \"owner\" | agentRole\n  reviewedAt    DateTime?\n  releaseReason String?          @db.Text\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([status])\n  @@index([contentHash])\n  @@map(\"quarantine_entries\")\n}\n\nmodel ImmunePattern {\n  id         String  @id @default(cuid())\n  businessId String? // null = shared\n\n  // Pattern detectat\n  patternType String // \"repeated_keyword\" | \"source_abuse\" | \"role_overreach\" | \"data_anomaly\"\n  patternKey  String // cheia unică a pattern-ului (ex: hash keywords)\n  description String @db.Text\n\n  // Statistici\n  occurrenceCount Int      @default(1)\n  firstSeenAt     DateTime @default(now())\n  lastSeenAt      DateTime @default(now())\n  violationIds    String[] // IDs ale violărilor care l-au format\n\n  // Răspuns automatic\n  autoBlock Boolean @default(false) // activat după threshold\n  threshold Int     @default(3) // de câte ori trebuie detectat înainte de autoBlock\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([businessId, patternType, patternKey])\n  @@index([isActive, autoBlock])\n  @@map(\"immune_patterns\")\n}\n\nenum BoundaryRuleType {\n  MORAL_CORE // violează principiile morale (CÂMP, Hawkins <200)\n  SCOPE_VIOLATION // agent acționează în afara competențelor\n  CONSISTENCY // contradicție cu decizii/politici existente\n  DATA_INTEGRITY // date corupte, format invalid, valori imposibile\n  PRIVACY // GDPR, date personale, pseudonimizare\n}\n\nenum BoundarySeverity {\n  CRITICAL // blocare imediată, escalare Owner\n  HIGH // blocare, notificare\n  MEDIUM // avertisment, log\n  LOW // doar log\n}\n\nenum BoundaryAction {\n  BLOCK // oprește acțiunea\n  QUARANTINE // izolează pentru review\n  WARN // permite dar avertizează\n  LOG // doar înregistrează\n}\n\nenum QuarantineStatus {\n  QUARANTINED // izolat, în așteptare review\n  RELEASED // Owner a aprobat\n  DESTROYED // Owner a respins definitiv\n  AUTO_RELEASED // pattern recunoscut ca false positive\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// STRATUL E — METABOLISM & LIFECYCLE (resurse + faze)\n// ═══════════════════════════════════════════════════════════════════════════════\n//\n// E1: Metering — cost energetic per agent/decizie (API calls, DB, timp)\n// E2: Resource market — agenți negociază capacitate la load shift\n// E3: Lifecycle phases — business-ul trece prin faze cu comportament diferit\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel ResourceUsage {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Cine consumă\n  agentRole  String\n  actionType String // \"cycle\" | \"evaluation\" | \"brainstorm\" | \"kb_query\" | \"client_chat\"\n\n  // Ce consumă\n  llmTokensIn  Int   @default(0)\n  llmTokensOut Int   @default(0)\n  llmCostUsd   Float @default(0)\n  dbQueries    Int   @default(0)\n  durationMs   Int   @default(0)\n\n  // Context\n  triggerSource String? // objectiveId, patchId, escalationId\n  metadata      Json? // detalii suplimentare\n\n  measuredAt DateTime @default(now())\n\n  @@index([businessId, agentRole, measuredAt])\n  @@index([businessId, measuredAt])\n  @@index([agentRole, actionType])\n  @@map(\"resource_usage\")\n}\n\nmodel ResourceBudget {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Cine primește buget\n  agentRole String\n\n  // Limite per perioadă (24h rolling)\n  maxLlmTokensPerDay  Int   @default(100000)\n  maxLlmCostPerDay    Float @default(5.0) // USD\n  maxCyclesPerDay     Int   @default(50)\n  maxDurationMsPerDay Int   @default(300000) // 5 min\n\n  // Stare curentă (rolling, recalculat periodic)\n  usedLlmTokens  Int      @default(0)\n  usedLlmCost    Float    @default(0)\n  usedCycles     Int      @default(0)\n  usedDurationMs Int      @default(0)\n  lastResetAt    DateTime @default(now())\n\n  // Prioritate (influențează alocarea la negociere)\n  priority Int @default(50) // 0-100\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([businessId, agentRole])\n  @@index([businessId, isActive])\n  @@map(\"resource_budgets\")\n}\n\nmodel ResourceNegotiation {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Cerere\n  requestorRole   String // agentul care cere mai mult\n  donorRole       String? // agentul care cedează (null = pool comun)\n  resourceType    String // \"llm_tokens\" | \"cycles\" | \"duration\"\n  amountRequested Int\n  amountGranted   Int     @default(0)\n\n  // Motivație\n  reason      String  @db.Text\n  objectiveId String? // legat de un obiectiv\n\n  // Status\n  status    NegotiationStatus @default(PENDING)\n  decidedBy String? // \"auto\" | \"owner\" | agentRole\n  decidedAt DateTime?\n\n  createdAt DateTime @default(now())\n\n  @@index([businessId, status])\n  @@index([requestorRole])\n  @@map(\"resource_negotiations\")\n}\n\nenum NegotiationStatus {\n  PENDING // în așteptare\n  GRANTED // aprobat (parțial sau total)\n  DENIED // respins\n  AUTO_GRANTED // aprobat automat (sub threshold)\n  EXPIRED // timeout fără decizie\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// STRATUL F — EVOLUTION (pruning + propagare selectivă)\n// ═══════════════════════════════════════════════════════════════════════════════\n//\n// F1: KB pruning — entries cu usage 0 pe 90 zile → review → Owner aprobă\n// F2: Selective propagation — comportament de succes → propagat la agenți similari\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel PruneCandidate {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Ce e candidat la pruning\n  entityType  String // \"kb_entry\" | \"brainstorm_idea\" | \"boundary_rule\" | \"homeostatic_target\"\n  entityId    String\n  entityTitle String // snapshot titlu pentru review fără join\n\n  // De ce\n  reason  PruneReason\n  score   Float // 0-100, mai mare = mai candidat la ștergere\n  metrics Json // { usageCount, daysSinceUsed, successRate, ... }\n\n  // Status\n  status     PruneStatus @default(FLAGGED)\n  reviewedBy String?\n  reviewedAt DateTime?\n  reviewNote String?     @db.Text\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([entityType, entityId])\n  @@index([businessId, status])\n  @@index([status, score])\n  @@map(\"prune_candidates\")\n}\n\nmodel PropagationEvent {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Ce se propagă\n  sourceRole String // agentul cu comportamentul de succes\n  sourceType String // \"kb_entry\" | \"behavior_patch\" | \"action_pattern\"\n  sourceId   String // ID-ul entității sursă\n\n  // Către cine\n  targetRoles     String[] // agenții care primesc\n  propagationType PropagationType\n\n  // Motivație (bazat pe outcome, nu pe broadcast)\n  outcomeId      String? // ServiceOutcome care a demonstrat succesul\n  successMetric  String // ce metric a fost îmbunătățit\n  improvementPct Float // cu cât %\n\n  // Status\n  status      PropagationStatus @default(PROPOSED)\n  appliedAt   DateTime?\n  confirmedAt DateTime?\n  revertedAt  DateTime?\n\n  createdAt DateTime @default(now())\n\n  @@index([businessId, status])\n  @@index([sourceRole])\n  @@map(\"propagation_events\")\n}\n\nenum PruneReason {\n  UNUSED_90D // 0 usage în 90 zile\n  LOW_SUCCESS_RATE // successRate < 20%\n  SUPERSEDED // înlocuit de entry mai nou cu aceleași tags\n  CONTRADICTED // contrazis de entries mai noi\n  EXPIRED // date expirate (ex: legislație veche)\n}\n\nenum PruneStatus {\n  FLAGGED // identificat automat\n  APPROVED // Owner a aprobat ștergerea\n  KEPT // Owner a decis să păstreze\n  PRUNED // șters efectiv\n  DEFERRED // amânat pentru review ulterior\n}\n\nenum PropagationType {\n  KB_CLONE // entry KB clonat la alți agenți\n  PATCH_TEMPLATE // behavior patch reutilizat\n  PATTERN_SHARE // pattern de acțiune documentat și partajat\n}\n\nenum PropagationStatus {\n  PROPOSED // propus pe baza outcome\n  APPROVED // Owner aprobat\n  APPLIED // propagat efectiv\n  CONFIRMED // target agents confirmă utilitatea\n  REVERTED // revertat — nu a funcționat la target\n  REJECTED // Owner respins\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// STRATUL G — RHYTHM & META (cadență + auto-observare)\n// ═══════════════════════════════════════════════════════════════════════════════\n//\n// G1: Service Outcomes — metric singular de rezultat real per serviciu\n// G2: Wild Cards — prompt ieșit din rutină, 1x/săpt per agent\n// G3: Rituals — retrospectivă, post-incident review, review lunar\n// G4: Meta-metrics — OODA timing, KB velocity, theme-to-action latency\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel ServiceOutcome {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Ce serviciu\n  serviceCode String // ex: \"b2b_s1_evaluare\", \"b2c_card1\", \"b2b_s3_calitate\"\n  serviceName String\n\n  // Metric singular de rezultat real\n  metricName   String // ex: \"client_retention_6m\", \"evaluation_accuracy_vs_expert\"\n  metricUnit   String // ex: \"%\", \"score\", \"days\"\n  targetValue  Float // ce vrem să atingem\n  currentValue Float? // ultimă măsurătoare\n\n  // Cum colectăm\n  collectionMethod    String // \"client_feedback\" | \"automated\" | \"manual_review\" | \"a_b_test\"\n  collectionFrequency String // \"per_session\" | \"monthly\" | \"quarterly\"\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  measurements OutcomeMeasurement[]\n\n  @@unique([businessId, serviceCode])\n  @@index([businessId, isActive])\n  @@map(\"service_outcomes\")\n}\n\nmodel OutcomeMeasurement {\n  id        String         @id @default(cuid())\n  outcomeId String\n  outcome   ServiceOutcome @relation(fields: [outcomeId], references: [id])\n\n  // Măsurătoare\n  value      Float\n  measuredAt DateTime @default(now())\n  source     String // \"client_survey\" | \"system_auto\" | \"owner_manual\" | \"a_b_result\"\n  notes      String?  @db.Text\n\n  // Context\n  tenantId  String? // per client (dacă relevant)\n  sessionId String? // per sesiune (dacă relevant)\n\n  createdAt DateTime @default(now())\n\n  @@index([outcomeId, measuredAt])\n  @@map(\"outcome_measurements\")\n}\n\nmodel WildCard {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Ținta\n  targetRole String // agentul care primește provocarea\n  weekOf     DateTime // săptămâna (luni) — un wild card per agent per săptămână\n\n  // Provocarea\n  prompt     String       @db.Text // provocarea generată\n  promptType WildCardType\n\n  // Răspunsul\n  response    String?   @db.Text\n  respondedAt DateTime?\n\n  // Evaluarea COG\n  cogReview        String? @db.Text\n  cogScore         Int? // 0-100 (originalitate + fezabilitate)\n  promotedToIdea   Boolean @default(false) // dacă devine BrainstormIdea\n  brainstormIdeaId String?\n\n  createdAt DateTime @default(now())\n\n  @@unique([targetRole, weekOf])\n  @@index([businessId, weekOf])\n  @@map(\"wild_cards\")\n}\n\nmodel Ritual {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Identitate\n  code        String // slug unic per business\n  name        String\n  description String?    @db.Text\n  ritualType  RitualType\n\n  // Programare\n  cronExpression String // ex: \"0 17 * * 5\" (vineri 17:00)\n  timezone       String @default(\"Europe/Bucharest\")\n\n  // Template\n  templatePrompt   String   @db.Text // prompt-ul care se execută\n  participantRoles String[] // agenții care participă\n  outputTarget     String // \"ntfy\" | \"kb\" | \"brainstorm\" | \"report\"\n\n  // Stare\n  lastRunAt     DateTime?\n  lastRunStatus String? // \"success\" | \"failed\" | \"skipped\"\n  runCount      Int       @default(0)\n\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([businessId, code])\n  @@index([isActive, ritualType])\n  @@map(\"rituals\")\n}\n\nmodel AdaptationMetric {\n  id         String @id @default(cuid())\n  businessId String\n\n  // Ce se măsoară\n  metricCode String // \"ooda_loop_time\" | \"kb_change_velocity\" | \"theme_to_action_latency\" | \"patch_effectiveness\"\n  metricName String\n\n  // Valoare\n  value      Float\n  unit       String // \"hours\" | \"entries/day\" | \"ms\" | \"%\"\n  measuredAt DateTime @default(now())\n\n  // Context\n  windowDays Int   @default(7) // fereastră de calcul\n  breakdown  Json? // detalii per agent/serviciu\n\n  createdAt DateTime @default(now())\n\n  @@index([businessId, metricCode, measuredAt])\n  @@index([measuredAt])\n  @@map(\"adaptation_metrics\")\n}\n\nenum WildCardType {\n  CONTRARIAN // \"Ce-ar fi dacă faci exact opusul a ce faci acum?\"\n  CROSS_DOMAIN // \"Cum ar rezolva problema X un [alt domeniu]?\"\n  FUTURE_SELF // \"Cum va arăta munca ta peste 2 ani? Ce faci acum care nu va mai fi relevant?\"\n  CONSTRAINT // \"Dacă ai avea doar 10% din resurse, ce ai păstra?\"\n  ABSURD // \"Cel mai nebunesc lucru pe care l-ai putea propune?\"\n}\n\nenum RitualType {\n  RETROSPECTIVE // review săptămânal\n  POST_INCIDENT // post-mortem după incident\n  STRATEGIC // review lunar strategic\n  CELEBRATION // celebrare outcomes atinse\n  CALIBRATION // recalibrare praguri + reguli\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// SALES PIPELINE — Lead tracking B2B\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel Lead {\n  id           String  @id @default(cuid())\n  companyName  String\n  contactName  String\n  contactEmail String\n  contactRole  String?\n  contactPhone String?\n  companySize  String? // \"10-50\", \"50-200\", \"200-500\", \"500+\"\n  industry     String?\n  website      String?\n\n  // Pipeline\n  stage  LeadStage  @default(NEW)\n  source LeadSource @default(MANUAL)\n  score  Int        @default(0) // BANT score 0-100\n\n  // BANT qualification\n  bantBudget    Boolean?\n  bantAuthority Boolean?\n  bantNeed      Boolean?\n  bantTimeline  Boolean?\n  bantNotes     String?  @db.Text\n\n  // Assignment\n  assignedAgent String  @default(\"SOA\")\n  tenantId      String? // NULL until CLOSED_WON\n  threadId      String? // ConversationThread link\n\n  // Email sequence tracking\n  lastEmailSentAt   DateTime?\n  emailSequenceStep Int       @default(0) // 0=none, 1=outreach, 2=followup1, 3=followup2\n  nextFollowUpAt    DateTime?\n\n  // Pipeline timestamps\n  qualifiedAt    DateTime?\n  demoAt         DateTime?\n  proposalSentAt DateTime?\n  closedAt       DateTime?\n  lostReason     String?\n  notes          String?   @db.Text\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([stage])\n  @@index([contactEmail])\n  @@index([nextFollowUpAt])\n  @@index([assignedAgent])\n  @@map(\"leads\")\n}\n\nenum LeadStage {\n  NEW\n  QUALIFIED\n  DEMO_SCHEDULED\n  DEMO_DONE\n  PROPOSAL\n  NEGOTIATION\n  CLOSED_WON\n  ONBOARDING\n  ACTIVE\n  CLOSED_LOST\n}\n\nenum LeadSource {\n  OUTBOUND_EMAIL\n  INBOUND_WEBSITE\n  REFERRAL\n  LINKEDIN\n  EVENT\n  MANUAL\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// B2C — Platforma de evoluție personală\n// Pseudonim default (GDPR by design), profil legat de alias nu identitate reală\n// ═══════════════════════════════════════════════════════════════════════════════\n\n/// Client B2C — cont anonim bazat pe pseudonim\nmodel B2CUser {\n  id            String        @id @default(cuid())\n  alias         String        @unique // \"numele de crisalidă\"\n  email         String        @unique // alias@jobgrade.ro (generat automat)\n  passwordHash  String?\n  age           Int?\n  gender        Gender?\n  lastJobTitle  String? // ultimul job avut\n  hasCurrentJob Boolean? // job curent da/nu\n  locale        String        @default(\"ro\")\n  status        B2CUserStatus @default(ONBOARDING)\n  lastLoginAt   DateTime?\n  createdAt     DateTime      @default(now())\n  updatedAt     DateTime      @updatedAt\n\n  // GDPR Art.17 — soft delete (VUL-027)\n  deletedAt          DateTime? // marcaj ștergere soft\n  deleteScheduledFor DateTime? // data hard delete (deletedAt + 30 zile)\n\n  // Profil evolutiv\n  profile        B2CProfile?\n  // Carduri și progres\n  cards          B2CCardProgress[]\n  // Sesiuni dialog\n  sessions       B2CSession[]\n  // Credite\n  creditBalance  B2CCreditBalance?\n  creditTxns     B2CCreditTransaction[]\n  // Comunități\n  memberships    B2CCommunityMember[]\n  // Teste parcurse\n  testResults    B2CTestResult[]\n  // Traseu evolutiv\n  evolutionLog   B2CEvolutionEntry[]\n  // Jurnal\n  journalEntries B2CJournalEntry[]\n\n  @@index([deleteScheduledFor])\n  @@index([status])\n  @@map(\"b2c_users\")\n}\n\n/// Profilul evolutiv — agregat din toate cele 5 fluxuri de profilare\nmodel B2CProfile {\n  id     String  @id @default(cuid())\n  userId String  @unique\n  user   B2CUser @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Herrmann HBDI — cadranele (0-100 fiecare)\n  herrmannA Float? // Analitic (stânga-sus, albastru)\n  herrmannB Float? // Secvențial (stânga-jos, verde)\n  herrmannC Float? // Interpersonal (dreapta-jos, roșu)\n  herrmannD Float? // Imaginativ (dreapta-sus, galben)\n\n  // Hawkins — nivel estimat pe scala conștiinței (observat, nu declarat)\n  hawkinsEstimate   Int? // 0-1000\n  hawkinsConfidence Float? // 0-1, cât de sigur e estimarea\n\n  // VIA Character Strengths — top 5 signature + bottom 3 necultivate\n  viaSignature   String[] // ex: [\"curiosity\", \"honesty\", \"kindness\"]\n  viaUndeveloped String[] // ex: [\"prudence\", \"self-regulation\"]\n\n  // Coordonata spirală globală (cel mai avansat nivel atins pe orice card)\n  spiralLevel Int @default(1) // 1=crisalidă, 2=fluture, 3=zbor, 4=salt\n  spiralStage Int @default(1) // etapa competenței 1-4\n\n  // Profilare din dialog (insights agregate)\n  dialogInsights Json? // structured insights din conversații\n  // Profilare din teste externe (licențiate)\n  externalTests  Json? // rezultate din teste parteneri, cu referință licență\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"b2c_profiles\")\n}\n\n/// Progresul clientului pe fiecare card\nmodel B2CCardProgress {\n  id     String  @id @default(cuid())\n  userId String\n  user   B2CUser @relation(fields: [userId], references: [id], onDelete: Cascade)\n  card   B2CCard // cardul (CARD_1..CARD_6)\n\n  status B2CCardStatus  @default(LOCKED) // LOCKED, ACTIVE, COMPLETED\n  // Spirala per card\n  phase  B2CSpiralPhase @default(CHRYSALIS) // faza pe acest card\n  stage  Int            @default(1) // etapa competenței 1-4\n\n  // Chestionar completat la activare card\n  questionnaireData Json? // răspunsurile la mini-chestionarul cardului\n\n  // Comunitate\n  communityReady     Boolean   @default(false) // agentul evaluează readiness\n  communityGrantedAt DateTime?\n\n  // CV (doar Card 3)\n  cvFileUrl       String? // S3/Blob URL\n  cvExtractedData Json? // extracție AI din CV → format fișă post\n\n  activatedAt DateTime?\n  completedAt DateTime?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  @@unique([userId, card])\n  @@index([userId, status])\n  @@map(\"b2c_card_progress\")\n}\n\n/// Sesiune de dialog B2C — o conversație cu un agent pe un card\nmodel B2CSession {\n  id        String  @id @default(cuid())\n  userId    String\n  user      B2CUser @relation(fields: [userId], references: [id], onDelete: Cascade)\n  card      B2CCard // pe ce card se desfășoară\n  agentRole String // CALAUZA, PROFILER, CAREER_COUNSELOR, etc.\n\n  // Jaloane sesiune (J0-J7)\n  milestones Json? // array de { milestone: \"J0\"..\"J7\", reachedAt: timestamp }\n\n  // Context invizibil — ce a primit agentul la start\n  contextSnapshot Json? // snapshot profil + interacțiuni relevante\n\n  status    B2CSessionStatus @default(ACTIVE)\n  startedAt DateTime         @default(now())\n  endedAt   DateTime?\n\n  // Link la ConversationThread (reutilizăm infrastructure existentă)\n  threadId String?\n\n  @@index([userId, card])\n  @@index([userId, agentRole])\n  @@map(\"b2c_sessions\")\n}\n\n/// Rezultat test — din L2 intern sau de la parteneri externi\nmodel B2CTestResult {\n  id       String        @id @default(cuid())\n  userId   String\n  user     B2CUser       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  testType B2CTestType // HERRMANN, VIA, HAWKINS, EXTERNAL_LICENSED\n  testName String // numele testului (ex: \"HBDI Full\", \"VIA-IS 120\", \"NEO-PI-R\")\n  source   B2CTestSource // INTERNAL_L2, EXTERNAL_PARTNER\n\n  // Rezultate\n  rawScore  Json // scorul brut complet\n  normScore Json? // scorul normalizat/interpretat\n  scoring   Json? // metoda de scorare aplicată\n\n  // Licență (pentru teste externe)\n  partnerId  String? // identificator partener licențiat\n  licenseRef String? // referință contract/licență\n\n  // Supervizare\n  supervisedBy String? // psiholog CPR care supervizează\n\n  administeredAt DateTime @default(now())\n  createdAt      DateTime @default(now())\n\n  @@index([userId, testType])\n  @@map(\"b2c_test_results\")\n}\n\n/// Intrare în traseul evolutiv — fiecare moment semnificativ\nmodel B2CEvolutionEntry {\n  id     String           @id @default(cuid())\n  userId String\n  user   B2CUser          @relation(fields: [userId], references: [id], onDelete: Cascade)\n  card   B2CCard // pe ce card s-a întâmplat\n  type   B2CEvolutionType // ce tip de moment\n\n  // Detalii\n  title       String // titlu scurt vizibil clientului\n  description String?        @db.Text // descriere extinsă\n  phase       B2CSpiralPhase // faza la momentul evenimentului\n  stage       Int // etapa competenței\n\n  // Metadata\n  sessionId String? // sesiunea în care s-a întâmplat\n  agentRole String? // agentul care a observat\n  metadata  Json? // date suplimentare (scor, detalii test, etc.)\n\n  createdAt DateTime @default(now())\n\n  @@index([userId, card, createdAt])\n  @@index([userId, createdAt])\n  @@map(\"b2c_evolution_entries\")\n}\n\n/// Comunitate B2C — una per card, acces condiționat\nmodel B2CCommunity {\n  id          String  @id @default(cuid())\n  card        B2CCard @unique // o singură comunitate per card\n  name        String // ex: \"Drumul către mine — Comunitatea\"\n  description String? @db.Text\n  isActive    Boolean @default(true)\n\n  members  B2CCommunityMember[]\n  messages B2CCommunityMessage[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"b2c_communities\")\n}\n\n/// Membru comunitate — prin pseudonim, acces condiționat de agent\nmodel B2CCommunityMember {\n  id          String       @id @default(cuid())\n  communityId String\n  community   B2CCommunity @relation(fields: [communityId], references: [id], onDelete: Cascade)\n  userId      String\n  user        B2CUser      @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Acces condiționat\n  grantedBy   String // agentRole care a acordat accesul\n  grantReason String? // motivul acordării\n\n  role     B2CCommunityRole @default(MEMBER)\n  joinedAt DateTime         @default(now())\n\n  @@unique([communityId, userId])\n  @@map(\"b2c_community_members\")\n}\n\n/// Mesaj în comunitate — prin pseudonim\nmodel B2CCommunityMessage {\n  id          String       @id @default(cuid())\n  communityId String\n  community   B2CCommunity @relation(fields: [communityId], references: [id], onDelete: Cascade)\n  authorId    String // B2CUser.id (afișat ca alias, nu identitate)\n  content     String       @db.Text\n  metadata    Json? // flaguri moderare, etc.\n\n  // Moderare\n  flaggedBy  String? // SAFETY_MONITOR, agent, etc.\n  flagReason String?\n  isVisible  Boolean @default(true)\n\n  createdAt DateTime @default(now())\n\n  @@index([communityId, createdAt])\n  @@map(\"b2c_community_messages\")\n}\n\n/// Credite B2C — separate de B2B\nmodel B2CCreditBalance {\n  id        String   @id @default(cuid())\n  userId    String   @unique\n  user      B2CUser  @relation(fields: [userId], references: [id], onDelete: Cascade)\n  balance   Int      @default(0)\n  updatedAt DateTime @updatedAt\n\n  @@map(\"b2c_credit_balances\")\n}\n\n/// Tranzacții credite B2C\nmodel B2CCreditTransaction {\n  id          String           @id @default(cuid())\n  userId      String\n  user        B2CUser          @relation(fields: [userId], references: [id], onDelete: Cascade)\n  type        B2CCreditTxnType\n  amount      Int // pozitiv = adăugare, negativ = consum\n  description String\n  card        B2CCard? // cardul pentru care s-au consumat creditele\n  sourceId    String? // referință Stripe payment, etc.\n  createdAt   DateTime         @default(now())\n\n  @@index([userId, createdAt])\n  @@map(\"b2c_credit_transactions\")\n}\n\n/// Intrare de jurnal — scrisă de client, adaptată la profilul cognitiv\nmodel B2CJournalEntry {\n  id     String  @id @default(cuid())\n  userId String\n  user   B2CUser @relation(fields: [userId], references: [id], onDelete: Cascade)\n  card   B2CCard // pe ce card a fost generat prompt-ul\n\n  // Prompt-ul adaptat (ce a primit clientul)\n  promptText       String  @db.Text\n  // Răspunsul clientului\n  content          String? @db.Text\n  // Durata sugerată vs. reală\n  suggestedMinutes Int\n  actualMinutes    Int?\n\n  // Calibrare cognitivă (snapshot la momentul generării)\n  herrmannDominance String? // A, B, C, D, AB, CD, etc.\n  dosageLevel       String? // SEED, SPROUT, GROWING, DEEPENING, FULL\n  spiralPhase       B2CSpiralPhase @default(CHRYSALIS)\n  competenceStage   Int            @default(1)\n\n  // Scop intern (invizibil clientului)\n  internalPurpose String?\n  targetDimension String? // dimensiunea din Evolution Engine\n\n  status    B2CJournalStatus @default(PROMPT_SENT)\n  createdAt DateTime         @default(now())\n  writtenAt DateTime? // când a scris clientul\n  updatedAt DateTime         @updatedAt\n\n  @@index([userId, card, createdAt])\n  @@index([userId, status])\n  @@map(\"b2c_journal_entries\")\n}\n\nenum B2CJournalStatus {\n  PROMPT_SENT // prompt-ul a fost trimis, clientul nu a scris încă\n  WRITING // clientul a început să scrie\n  COMPLETED // clientul a terminat\n  SKIPPED // clientul a sărit (nu a vrut să scrie — informativ, nu punitiv)\n}\n\n// ── B2C Enums ────────────────────────────────────────────────────────────────\n\nenum B2CUserStatus {\n  ONBOARDING // alias creat, nu a terminat onboarding-ul\n  ACTIVE // cont activ, interacționează\n  INACTIVE // nu s-a logat >60 zile\n  SUSPENDED // suspendat (incident, plată, etc.)\n  DELETED // marcat pentru ștergere GDPR (soft delete, 30 zile grație)\n}\n\nenum B2CCard {\n  CARD_1 // \"Drumul către mine\" — Călăuza (nucleu)\n  CARD_2 // \"Eu și ceilalți, adică NOI\" — Consilier Dezvoltare Personală (relații)\n  CARD_3 // \"Îmi asum un rol profesional\" — Consilier Carieră (profesie)\n  CARD_4 // \"Oameni de succes / Oameni de valoare\" — Coach (tranziție)\n  CARD_5 // \"Eu și antreprenoriatul transformațional\" — Coach (integrare)\n  CARD_6 // \"Spune-mi despre mine\" — Profiler (transversal)\n}\n\nenum B2CCardStatus {\n  LOCKED // invizibil sau gri, neactivat\n  ACTIVE // activat (gratuit sau plătit)\n  COMPLETED // parcurs complet (rare — spirala e continuă)\n}\n\nenum B2CSpiralPhase {\n  CHRYSALIS // Crisalidă — \"Sunt cine cred că sunt\"\n  BUTTERFLY // Fluture — \"Văd că sunt mai mult decât credeam\"\n  FLIGHT // Zbor — \"Sunt cine sunt, fără mască\"\n  LEAP // Salt — \"Vreau să duc asta mai departe\"\n}\n\nenum B2CSessionStatus {\n  ACTIVE // sesiune în desfășurare\n  PAUSED // client a pus pauză (revine)\n  COMPLETED // sesiune încheiată natural\n  ESCALATED // escaladată la SAFETY_MONITOR\n}\n\nenum B2CEvolutionType {\n  MILESTONE // jalon atins pe spirală (J0-J7)\n  INSIGHT // moment de claritate / revelație\n  REGRESSION // regresie temporară (normală pe drum)\n  TRANSITION // tranziție între carduri\n  HANDOFF // predare ștafetă către alt agent/călăuză umană\n  TEST_RESULT // rezultat test integrat în profil\n  COMMUNITY // acces acordat la comunitate\n}\n\nenum B2CTestType {\n  HERRMANN // HBDI — profilul cognitiv\n  VIA // Character Strengths\n  HAWKINS // Scala conștiinței (estimat)\n  EXTERNAL_LICENSED // test extern, licențiat de la partener\n}\n\nenum B2CTestSource {\n  INTERNAL_L2 // instrumente din echipa de resurse suport\n  EXTERNAL_PARTNER // teste licențiate de la parteneri terți\n  OWNER_PROVIDED // teste încărcate de Owner cu metodă de scorare\n}\n\nenum B2CCreditTxnType {\n  PURCHASE // achiziție credite\n  CARD_ACTIVATION // consum la activare card\n  SERVICE // consum serviciu plătit (raport, consiliere, etc.)\n  REFUND // rambursare\n}\n\nenum B2CCommunityRole {\n  MEMBER // membru standard\n  MENTOR // fluture care ghidează crisalide\n  MODERATOR // moderator (agent AI sau uman)\n}\n\n// ── System Config (runtime toggles, no redeploy needed) ──────────────────────\n\nmodel SystemConfig {\n  key       String   @id\n  value     String\n  label     String?\n  updatedAt DateTime @updatedAt\n\n  @@map(\"system_config\")\n}\n\n// ─────────────────────────────────────────\n// PRICING & TELEMETRY (16.04.2026)\n// Algoritm: cost real → cost acoperitor → BNR+buffer → marjă\n// Vezi: project_pricing_methodology.md\n// Valorile concrete (cost, marjă, buffer) populate de COG după\n// răspunsul la cele 8 întrebări strategice.\n// ─────────────────────────────────────────\n\nmodel ProviderCost {\n  id              String   @id @default(cuid())\n  provider        String // \"anthropic\", \"vercel\", \"neon\", \"resend\", etc.\n  resourceType    String // \"haiku-4-5-input-tokens\", \"vercel-pro-monthly\", \"neon-launch-monthly\", etc.\n  unitMeasure     String // \"1M tokens\", \"1 month subscription\", \"1 client/month\", \"1 minute compute\"\n  costCategory    String   @default(\"OPEX_PER_EXECUTION\")\n  // CAPEX: lunar fix indiferent de volum (plan Vercel Pro, Neon Launch, salarii, marketing)\n  // OPEX_PER_CLIENT: incremental per cont nou activat (storage profil, backup, notificări baseline)\n  // OPEX_PER_EXECUTION: variabil per rulare/sesiune (tokens AI, compute, email, blob)\n  currentCostUSD  Decimal  @db.Decimal(20, 8) // preț real curent (informativ)\n  coveringCostUSD Decimal  @db.Decimal(20, 8) // preț acoperitor (folosit la calcul — worst case)\n  notes           String?  @db.Text // de ce e ales acest covering\n  effectiveFrom   DateTime @default(now())\n  updatedBy       String? // OWNER, COG, AUTOMATED_JOB\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n\n  @@unique([provider, resourceType, effectiveFrom])\n  @@index([provider, resourceType])\n  @@index([costCategory])\n  @@map(\"provider_costs\")\n}\n\nmodel AIOperationTier {\n  id                       String   @id @default(cuid())\n  operationType            String   @unique // \"intent-classification\", \"report-generation-je\", etc.\n  description              String?  @db.Text\n  currentModel             String // \"claude-haiku-4-5-20251001\"\n  coveringModel            String // \"claude-opus-4-6\" (folosit la calcul cost)\n  tokenAmplificationFactor Decimal  @default(1.0) @db.Decimal(5, 2) // 1.0-2.0 (Opus poate genera mai mult)\n  notes                    String?  @db.Text\n  effectiveFrom            DateTime @default(now())\n  updatedAt                DateTime @updatedAt\n\n  @@map(\"ai_operation_tiers\")\n}\n\nmodel ServiceUsageLog {\n  id               String  @id @default(cuid())\n  tenantId         String\n  userId           String?\n  serviceCode      String // ID serviciu (ex: \"je-evaluate\", \"consultant-hr-chat\")\n  executionVariant String  @default(\"AUTO\") // \"AUTO\" | \"HYBRID_AI_MEDIATED\" | \"HYBRID_HUMAN_MEDIATED\"\n  executionId      String? // ID execuție (sesiune chat, raport, etc.)\n  operationType    String? // mapare la AIOperationTier (dacă e operație AI)\n\n  // Telemetry brut\n  modelUsed      String? // model AI efectiv folosit\n  tokensInput    Int     @default(0)\n  tokensOutput   Int     @default(0)\n  computeMs      Int     @default(0)\n  dbReadBytes    Int     @default(0)\n  dbWriteBytes   Int     @default(0)\n  bandwidthBytes Int     @default(0)\n  emailsSent     Int     @default(0)\n  blobBytes      Int     @default(0)\n  humanMinutes   Decimal @default(0) @db.Decimal(8, 2) // pentru servicii mixte cu uman\n\n  // Cost calculat\n  costRealRON     Decimal? @db.Decimal(12, 4) // costul real (informativ)\n  costCoveringRON Decimal? @db.Decimal(12, 4) // costul acoperitor (folosit pentru margin)\n  creditsCharged  Decimal? @db.Decimal(10, 4) // credite debitate efectiv\n\n  metadata  Json? // payload suplimentar (ex: durata sesiune chat)\n  createdAt DateTime @default(now())\n\n  @@index([tenantId, createdAt])\n  @@index([serviceCode, createdAt])\n  @@index([userId, createdAt])\n  @@map(\"service_usage_logs\")\n}\n\nmodel ServicePricing {\n  id               String   @id @default(cuid())\n  serviceCode      String // \"je-evaluate\", \"pay-gap-report\", \"consultant-hr-chat\", etc.\n  serviceName      String\n  serviceType      String // \"REPORT\" | \"ASSISTANCE\" | \"PROCESS\"\n  // Variantă execuție — același serviciu poate avea 1-3 variante cu cost și\n  // preț distinct (AUTO, HYBRID_AI_MEDIATED, HYBRID_HUMAN_MEDIATED).\n  // Folosit de servicii de tip evaluare (JE, evaluare comună, mediere decalaj).\n  executionVariant String   @default(\"AUTO\") // \"AUTO\" | \"HYBRID_AI_MEDIATED\" | \"HYBRID_HUMAN_MEDIATED\"\n  unitMeasure      String // \"rulare\", \"minut\", \"intrebare\", \"sesiune\", \"angajat\", \"pozitie\"\n  // Tarifare mixtă CAPEX+OPEX:\n  // costInCredits = baza fixă (componenta CAPEX — setup, framework, infrastructură)\n  // perUnitCredits = variabila per unitate (componenta OPEX — scalează cu volumul)\n  // Formula: total = costInCredits + perUnitCredits × cantitate\n  // Dacă costInCredits = 0 → pur OPEX (doar per unitate)\n  // Dacă perUnitCredits = 0/null → preț fix per proiect (pur CAPEX sau preț flat)\n  costInCredits    Decimal  @db.Decimal(10, 4) // baza fixă (credite)\n  perUnitCredits   Decimal? @db.Decimal(10, 4) // variabil per unitate (credite) — null = preț fix\n  perUnitLabel     String? // denumire unitate variabilă (ex: \"angajat\", \"poziție\") — pt afișare\n  marginMultiplier Decimal? @db.Decimal(5, 2) // factor multiplicare cost intern → preț (informativ)\n  chatTier         String? // \"FAMILIARIZARE\" | \"CONSULTANTA\" (doar pentru ASSISTANCE)\n  isFreeTier       Boolean  @default(false)\n  freeTierLimit    Int?\n  freeTierUnit     String?\n  effectiveFrom    DateTime @default(now())\n  notes            String?  @db.Text\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n\n  @@unique([serviceCode, executionVariant, chatTier, effectiveFrom])\n  @@index([serviceCode])\n  @@index([serviceCode, executionVariant])\n  @@map(\"service_pricing\")\n}\n\nmodel CreditValue {\n  id                  String   @id @default(cuid())\n  bnrUsdRonRate       Decimal  @db.Decimal(10, 4) // cursul BNR USD→RON la data efectiva\n  bnrEurRonRate       Decimal? @db.Decimal(10, 4) // cursul BNR EUR→RON (pentru furnizori EUR)\n  bufferPercent       Decimal  @default(5.0) @db.Decimal(5, 2) // buffer peste BNR (decizie COG)\n  effectiveUsdRonRate Decimal  @db.Decimal(10, 4) // BNR × (1 + buffer/100) — folosit la conversie\n  valuePerCreditRON   Decimal  @db.Decimal(8, 4) // RON per 1 credit (decizie COG)\n  effectiveFrom       DateTime @default(now())\n  notes               String?  @db.Text\n  createdAt           DateTime @default(now())\n\n  @@map(\"credit_values\")\n}\n\n// ─────────────────────────────────────────\n// ORGANISM INTELLIGENT — CRONURI INTELIGENTE\n// Arhitectura: threshold → KB-first → alignment → cost-gate → executor → learning → telemetry\n// ─────────────────────────────────────────\n\nmodel ExecutionTelemetry {\n  id                String   @id @default(cuid())\n  taskId            String?\n  agentRole         String\n  taskType          String?\n  modelUsed         String // \"haiku\" | \"sonnet\" | \"opus\"\n  tokensInput       Int      @default(0)\n  tokensOutput      Int      @default(0)\n  estimatedCostUSD  Float    @default(0)\n  kbHit             Boolean  @default(false)\n  kbSimilarityScore Float?\n  alignmentResult   String   @default(\"SKIPPED\") // ALIGNED | UNCERTAIN | MISALIGNED | SKIPPED\n  alignmentLevel    Int? // 1-5 la ce nivel s-a rezolvat alinierea\n  thresholdPassed   Boolean  @default(true)\n  durationMs        Int      @default(0)\n  webSearchCount    Int      @default(0)\n  learningCreated   Boolean  @default(false)\n  isInternal        Boolean  @default(true) // true = consum organism, false = consum client\n  createdAt         DateTime @default(now())\n\n  @@index([agentRole, createdAt])\n  @@index([createdAt])\n  @@map(\"execution_telemetry\")\n}\n\nmodel LearningArtifact {\n  id                 String    @id @default(cuid())\n  problemClass       String // clasificare problema (ex: \"alignment-check\", \"kb-gap\", \"escalation-pattern\")\n  rule               String    @db.Text // regula extrasa\n  example            String    @db.Text // exemplu concret\n  antiPattern        String?   @db.Text // ce NU trebuie facut\n  sourceEscalationId String? // task-ul care a generat artefactul\n  teacherRole        String // cine a produs artefactul (agentul care a rezolvat)\n  studentRole        String // cui i-a fost livrat (agentul care a escalat)\n  sourceType         String    @default(\"ESCALATION\") // ESCALATION | POST_EXECUTION | EXTRAPOLATION\n  appliedCount       Int       @default(0) // de cate ori a fost aplicat cu succes\n  effectivenessScore Float     @default(0) // 0-1, creste cu fiecare aplicare reusita\n  validated          Boolean   @default(false) // true = folosit cu succes în task aprobat de manager\n  expiresAt          DateTime? // expirare daca nu e folosit >90 zile\n  createdAt          DateTime  @default(now())\n  updatedAt          DateTime  @updatedAt\n\n  @@index([studentRole, problemClass])\n  @@index([teacherRole])\n  @@map(\"learning_artifacts\")\n}\n\nmodel AgentBudget {\n  id                 String   @id @default(cuid())\n  agentRole          String   @unique\n  dailyLimitTokens   Int      @default(20000)\n  monthlyLimitTokens Int      @default(500000)\n  alertThreshold     Float    @default(0.8) // 80% din limita\n  currentDailyUsed   Int      @default(0)\n  currentMonthlyUsed Int      @default(0)\n  lastResetDaily     DateTime @default(now())\n  lastResetMonthly   DateTime @default(now())\n  createdAt          DateTime @default(now())\n  updatedAt          DateTime @updatedAt\n\n  @@map(\"agent_budgets\")\n}\n\nmodel AlignmentLog {\n  id              String   @id @default(cuid())\n  taskId          String?\n  agentRole       String\n  actionSummary   String   @db.Text // ce voia sa faca\n  level           Int // 1-5: la ce nivel s-a rezolvat\n  result          String // ALIGNED | UNCERTAIN | MISALIGNED | EXTRAPOLATED\n  resolvedBy      String? // agentRole care a rezolvat (daca escalat/extrapolat)\n  reasoning       String?  @db.Text // justificare\n  artifactCreated Boolean  @default(false) // a generat LearningArtifact\n  costTokens      Int      @default(0) // tokens consumate pentru verificare (0 la Nivel 1-3)\n  createdAt       DateTime @default(now())\n\n  @@index([agentRole, createdAt])\n  @@index([level, result])\n  @@map(\"alignment_logs\")\n}\n\n// ═══════════════════════════════════════════════════════════════════════════════\n// SUPORT CLIENT — Ticketing + Rezolvare + Învățare\n// ═══════════════════════════════════════════════════════════════════════════════\n\nmodel SupportTicket {\n  id        String @id @default(cuid())\n  tenantId  String // clientul B2B\n  createdBy String // userId care a creat ticketul\n\n  // Semnalare client (text brut, neinterpretat)\n  subject     String // titlu scurt\n  description String @db.Text // descrierea problemei\n\n  // Rafinare FW (după interogare suplimentară)\n  refinedDescription String? @db.Text // versiunea rafinată\n  affectedFlow       String? // fluxul afectat (vanzare/utilizare/plata/onboarding)\n\n  // Rutare\n  routedToAgent String? // agentul identificat cu atribuțiile potrivite\n  routedToDept  String? // departamentul\n  routedByCSA   Boolean @default(false) // CSA a făcut rutarea\n\n  // Rezolvare\n  status           SupportTicketStatus @default(NEW)\n  priority         AgentTaskPriority   @default(NECESAR)\n  resolutionTaskId String? // task-ul intern creat pentru rezolvare\n  resolution       String?             @db.Text // rezolvarea internă\n\n  // Răspuns client\n  clientResponse String?   @db.Text // răspunsul formulat pentru client (calibrat L2)\n  respondedAt    DateTime?\n  respondedBy    String? // agentul care a formulat răspunsul\n\n  // Satisfacție client\n  clientRating   Int? // 1-5\n  clientFeedback String?\n\n  // Învățare\n  distilled          Boolean @default(false) // s-a extras învățare?\n  learningArtifactId String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([tenantId, status])\n  @@index([status, priority])\n  @@index([routedToAgent, status])\n  @@map(\"support_tickets\")\n}\n\nenum SupportTicketStatus {\n  NEW // client tocmai a trimis\n  REFINING // FW rafinează cu clientul\n  ROUTED // CSA a rutat la agentul potrivit\n  IN_PROGRESS // se lucrează la rezolvare\n  RESOLVED // rezolvat intern, răspuns în curs\n  RESPONDED // răspuns trimis clientului\n  CLOSED // client a confirmat sau timeout\n  ESCALATED // escalat la nivel superior / Owner\n}\n\n// Partiție L2: secrete de serviciu (NU ajung la client-facing/profiler)\nmodel TradeSecret {\n  id          String   @id @default(cuid())\n  category    String // pricing-internal, algorithm, scoring-formula, strategy\n  content     String   @db.Text\n  accessLevel String   @default(\"INTERNAL_ONLY\") // INTERNAL_ONLY | MANAGEMENT | OWNER\n  createdBy   String\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@index([category])\n  @@index([accessLevel])\n  @@map(\"trade_secrets\")\n}\n\n// ─────────────────────────────────────────\n// CRAWLING ENGINE — Shared Infrastructure\n// ─────────────────────────────────────────\n\n/// Sursă de date externe (INS, topfirme, primărie, etc.)\nmodel CrawlSource {\n  id            String    @id @default(cuid())\n  name          String    @unique // ex: \"INS_TEMPO\", \"TOPFIRME\", \"PRIMARIE_MEDGIDIA\"\n  displayName   String // ex: \"INS TEMPO Online\"\n  url           String // URL bază\n  type          String // API | HTML_SCRAPER | RSS | PDF\n  schedule      String // cron expression: \"0 6 * * *\" = zilnic la 6\n  enabled       Boolean   @default(true)\n  territory     String? // localitate/județ/național — null = toate\n  lastCrawlAt   DateTime?\n  lastSuccessAt DateTime?\n  lastError     String?   @db.Text\n  totalCrawls   Int       @default(0)\n  totalRecords  Int       @default(0)\n  config        Json? // configurare specifică per sursă (headers, selectors, etc.)\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  results CrawlResult[]\n\n  @@map(\"crawl_sources\")\n}\n\n/// Rezultatul unei sesiuni de crawling\nmodel CrawlResult {\n  id             String   @id @default(cuid())\n  sourceId       String\n  crawledAt      DateTime @default(now())\n  status         String // SUCCESS | PARTIAL | FAILED\n  recordsFound   Int      @default(0)\n  recordsNew     Int      @default(0)\n  recordsUpdated Int      @default(0)\n  durationMs     Int      @default(0)\n  error          String?  @db.Text\n  metadata       Json? // statistici suplimentare per crawl\n\n  source CrawlSource @relation(fields: [sourceId], references: [id], onDelete: Cascade)\n\n  @@index([sourceId, crawledAt])\n  @@map(\"crawl_results\")\n}\n\n/// Date teritoriale normalizate (output crawling — consumate de agenți)\nmodel TerritorialData {\n  id           String   @id @default(cuid())\n  territory    String // cod SIRUTA sau \"MEDGIDIA\", \"JUD_CONSTANTA\", etc.\n  category     String // POPULATION | BUSINESS | INFRASTRUCTURE | EDUCATION | HEALTH | LABOR | ECONOMY\n  subcategory  String? // per categorie: AGE_GROUPS, CAEN_DISTRIBUTION, SCHOOLS, etc.\n  key          String // identificator unic per dată: \"pop_20_29\", \"firms_total\", etc.\n  value        String   @db.Text // valoare (număr, JSON, text)\n  numericValue Float? // valoare numerică (pentru comparații/sort)\n  unit         String? // \"persoane\", \"firme\", \"RON\", \"%\"\n  source       String // CrawlSource.name\n  sourceUrl    String? // URL exact de unde vine\n  periodYear   Int? // anul la care se referă datele\n  periodMonth  Int? // luna (opțional)\n  latitude     Float? // GPS\n  longitude    Float? // GPS\n  radius       Float? // raza de relevanță (km)\n  confidence   Float    @default(1.0) // 1.0 = sursă oficială, 0.5 = estimat\n  crawledAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@unique([territory, category, key, periodYear])\n  @@index([territory, category])\n  @@index([category, subcategory])\n  @@index([territory])\n  @@map(\"territorial_data\")\n}\n\n/// Entitate locală (firmă, instituție, serviciu) — GPS-mapped\nmodel LocalEntity {\n  id             String   @id @default(cuid())\n  territory      String // MEDGIDIA, etc.\n  type           String // BUSINESS | SCHOOL | HOSPITAL | PHARMACY | SERVICE | PERSON\n  name           String\n  description    String?  @db.Text\n  category       String? // CAEN, tip serviciu, etc.\n  subcategory    String?\n  address        String?\n  latitude       Float?\n  longitude      Float?\n  phone          String?\n  email          String?\n  website        String?\n  employees      Int?\n  revenue        Float? // cifră afaceri RON\n  source         String // crawl source sau \"CROWDSOURCED\"\n  sourceId       String? // CUI, cod unic, etc.\n  isActive       Boolean  @default(true)\n  isCrowdsourced Boolean  @default(false) // true = participant s-a înregistrat singur\n  metadata       Json? // date suplimentare specifice tipului\n  crawledAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  @@unique([territory, type, sourceId])\n  @@index([territory, type])\n  @@index([territory, latitude, longitude])\n  @@index([type, category])\n  @@map(\"local_entities\")\n}\n"
}

